export const GENERATED_QUIZZES: QuizItem[] = [
  // ── de (60 items) ──
  { id: "q-de-a1-gemini-1-mr5o63kk", question: "Ich ___ Student.", options: ["bin","ist","sind","seid"], answer: 0, explain: "For the first person singular pronoun 'ich' (I), the correct conjugation of the verb 'sein' (to be) is 'bin'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-2-mr5o63kk", question: "Du ___ einen Hund.", options: ["hat","habt","hast","haben"], answer: 2, explain: "For the second person singular pronoun 'du' (you), the correct conjugation of the verb 'haben' (to have) is 'hast'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-3-mr5o63kk", question: "Das ist ___ Tisch.", options: ["die","der","das","ein"], answer: 1, explain: "The noun 'Tisch' (table) is masculine, so the correct definite article in the nominative case is 'der'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-4-mr5o63kk", question: "Was ___ du?", options: ["machst","mache","macht","machen"], answer: 0, explain: "For the second person singular pronoun 'du' (you), the correct conjugation of the regular verb 'machen' (to make/do) is 'machst'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-5-mr5o63kk", question: "Sie hat ___ Tasche.", options: ["ein","eine","einen","einer"], answer: 1, explain: "The noun 'Tasche' (bag) is feminine, so the correct indefinite article in the nominative case is 'eine'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-6-mr5o63kk", question: "Das sind meine ___.", options: ["Buch","Bücher","Buchs","Buchen"], answer: 1, explain: "The plural form of 'Buch' (book) is 'Bücher'. The sentence uses 'sind' (are), indicating a plural noun is needed.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-7-mr5o63kk", question: "Ich komme ___ Deutschland.", options: ["in","auf","aus","mit"], answer: 2, explain: "The preposition 'aus' (from) is used to indicate origin or where someone comes from. 'Ich komme aus Deutschland' means 'I come from Germany'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-8-mr5o63kk", question: "Wir ___ Musik.", options: ["hören","hört","höre","hörst"], answer: 0, explain: "For the first person plural pronoun 'wir' (we), the correct conjugation of the regular verb 'hören' (to hear/listen) is 'hören'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-9-mr5o63kk", question: "Ist das ___ Auto?", options: ["die","der","das","ein"], answer: 2, explain: "The noun 'Auto' (car) is neuter, so the correct definite article in the nominative case is 'das'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-10-mr5o63kk", question: "Er ___ zur Arbeit.", options: ["geht","gehe","gehen","gehst"], answer: 0, explain: "For the third person singular pronoun 'er' (he), the correct conjugation of the irregular verb 'gehen' (to go) is 'geht'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-11-mr5o63kk", question: "Ich spreche ___ Spanisch.", options: ["nicht","kein","keine","nichts"], answer: 0, explain: "To negate a verb or an adjective, we use 'nicht'. Here, it negates the action of speaking Spanish.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-12-mr5o63kk", question: "___ wohnst du?", options: ["Was","Wie","Wer","Wo"], answer: 3, explain: "To ask about location, the correct question word is 'Wo' (Where). 'Wo wohnst du?' means 'Where do you live?'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-13-mr5o63kl", question: "Das ist ___ Mann.", options: ["ein","eine","einen","einer"], answer: 0, explain: "The noun 'Mann' (man) is masculine, so the correct indefinite article in the nominative case is 'ein'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-14-mr5o63kl", question: "___ ihr Deutsch?", options: ["Lernt","Lernst","Lerne","Lernen"], answer: 0, explain: "For the second person plural pronoun 'ihr' (you all), the correct conjugation of the regular verb 'lernen' (to learn) is 'lernt'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-15-mr5o63kl", question: "Ich bin ___ Berlin.", options: ["auf","zu","in","an"], answer: 2, explain: "To express being in a city, the preposition 'in' is typically used. 'Ich bin in Berlin' means 'I am in Berlin'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-16-mr5o63kl", question: "___ Kinder spielen im Garten.", options: ["Das","Der","Die","Ein"], answer: 2, explain: "The noun 'Kinder' (children) is plural, so the correct definite article in the nominative case is 'die' for all plural nouns.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-17-mr5o63kl", question: "___ du müde?", options: ["Bist","Seid","Sind","Ist"], answer: 0, explain: "For the second person singular pronoun 'du' (you), the correct conjugation of the verb 'sein' (to be) is 'bist'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-18-mr5o63kl", question: "Ich habe ___ Zeit.", options: ["nicht","kein","keine","keinen"], answer: 2, explain: "To negate a noun without an article, we use 'kein' (no, not a). 'Zeit' (time) is feminine, so the correct form is 'keine'.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-19-mr5o63kl", question: "Wir ___ Kaffee.", options: ["trinke","trinkst","trinken","trinkt"], answer: 2, explain: "With first-person plural subject 'wir' (we), the correct present tense conjugation is 'trinken'. 'trinkt' is for er/sie/es; 'trinkst' is for du; 'trinke' is for ich.", language: "de", level: "A1" },
  { id: "q-de-a1-gemini-20-mr5o63kl", question: "Wir wohnen ___ der Hauptstraße.", options: ["in","an","auf","mit"], answer: 0, explain: "We use 'in' for living on a street: 'in der Hauptstraße wohnen'. 'Hauptstraße' is feminine (die Hauptstraße), so dative takes 'der'. 'in der Hauptstraße' is the standard expression for living on this street.", language: "de", level: "A1" },
  { id: "q-de-a2-gemini-1-mr5o6i9y", question: "Gestern ___ ich einen interessanten Film im Kino gesehen.", options: ["habe","bin","hatte","war"], answer: 0, explain: "To form the present perfect (Perfekt) with most verbs, you use 'haben' as the auxiliary verb. 'Habe gesehen' is the correct Perfekt form for 'sehen'.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-2-mr5o6i9y", question: "Du ___ deine Hausaufgaben machen, bevor du spielst.", options: ["sollst","kannst","musst","willst"], answer: 2, explain: "'Müssen' means 'must' or 'have to' and expresses a strong obligation or necessity. The sentence implies that doing homework is a requirement before playing.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-3-mr5o6i9y", question: "Dieses Buch ist ___ als das andere.", options: ["interessant","interessanter","am interessantesten","meist interessant"], answer: 1, explain: "To form the comparative of adjectives, you usually add '-er'. 'Interessanter' means 'more interesting', which is appropriate when comparing two items using 'als' (than).", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-4-mr5o6i9y", question: "Ich kann heute nicht kommen, ___ ich viel arbeiten muss.", options: ["aber","und","weil","oder"], answer: 2, explain: "'Weil' means 'because' and introduces a subordinate clause. In a subordinate clause, the conjugated verb moves to the end of the sentence.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-5-mr5o6i9y", question: "Als ich ein Kind ___, spielte ich oft im Garten.", options: ["war","bin","habe gewesen","wäre"], answer: 0, explain: "The Präteritum (simple past) of 'sein' (to be) is 'war'. It is commonly used for 'sein' and 'haben' in past narratives, especially with 'als' (when) describing a past state.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-6-mr5o6i9y", question: "Er ist sehr müde, ___ er hat lange gearbeitet.", options: ["weil","aber","und","denn"], answer: 3, explain: "'Denn' means 'because' and is a coordinating conjunction. Unlike 'weil', 'denn' does not change the word order; the verb remains in the second position.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-7-mr5o6i9y", question: "Mein Auto ist ___ als deins.", options: ["alt","älter","älteste","am ältesten"], answer: 1, explain: "To form the comparative of 'alt' (old), you add '-er' and an umlaut: 'älter'. This is used with 'als' (than) to compare two things.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-8-mr5o6i9y", question: "Wir ___ Deutsch sprechen, wenn wir in Deutschland sind.", options: ["sollten","können","müssen","dürfen"], answer: 2, explain: "'Müssen' (must/have to) is the correct modal verb here, indicating a necessity or strong obligation to speak German in Germany.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-9-mr5o6i9y", question: "Ich ___ gestern nicht in der Schule.", options: ["bin","war","habe gewesen","sei"], answer: 1, explain: "The Präteritum (simple past) of 'sein' (to be) is 'war'. It is commonly used when speaking about past states, especially with time adverbs like 'gestern' (yesterday).", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-10-mr5o6i9y", question: "Sie ___ gut Klavier spielen.", options: ["muss","soll","kann","will"], answer: 2, explain: "'Können' means 'can' or 'to be able to' and expresses an ability. The sentence describes her skill at playing the piano.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-11-mr5o6i9y", question: "Das Wetter ist heute ___ als gestern.", options: ["schön","schöner","am schönsten","schönste"], answer: 1, explain: "The comparative form of 'schön' (beautiful/nice) is 'schöner'. It is used with 'als' (than) to compare two things.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-12-mr5o6i9y", question: "Wir gehen ins Kino ___ danach essen wir Pizza.", options: ["aber","weil","und","oder"], answer: 2, explain: "'Und' means 'and' and connects two clauses or phrases. It is a coordinating conjunction and does not change the word order of the clauses it connects.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-13-mr5o6i9y", question: "Warum ___ du gestern nicht angerufen?", options: ["bist","hast","warst","wurdest"], answer: 1, explain: "The verb 'anrufen' forms its Perfekt with 'haben'. Therefore, 'hast angerufen' is the correct form for the past tense question.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-14-mr5o6i9y", question: "Du ___ pünktlich sein, sonst verpasst du den Zug.", options: ["sollst","kannst","musst","darfst"], answer: 2, explain: "'Müssen' (must/have to) indicates a necessity or an important requirement. Being on time is crucial to avoid missing the train.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-15-mr5o6i9y", question: "Ich mag Kaffee, ___ mein Bruder trinkt lieber Tee.", options: ["und","weil","aber","obwohl"], answer: 2, explain: "'Aber' means 'but' and is a coordinating conjunction used to show contrast or opposition between two statements.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-16-mr5o6i9y", question: "Die Stadt ist ___ als das Dorf.", options: ["groß","größer","größte","am größten"], answer: 1, explain: "The comparative form of 'groß' (big) is 'größer'. It is used with 'als' (than) to compare two different places.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-17-mr5o6i9y", question: "Letztes Jahr ___ wir nach Italien gereist.", options: ["haben","sind","hatten","waren"], answer: 1, explain: "Verbs of movement to a destination, like 'reisen' (to travel), form their Perfekt (present perfect) with the auxiliary verb 'sein'.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-18-mr5o6i9y", question: "Er ist krank, ___ er kann nicht zur Arbeit gehen.", options: ["aber","und","deshalb","weil"], answer: 1, explain: "'Und' means 'and' and is used here to connect two related statements, where the second is a consequence of the first. 'Deshalb' would also fit logically but is not a basic conjunction in the scope.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-19-mr5o6i9y", question: "Ich ___ ein Eis, wenn das Wetter schön ist.", options: ["möchte","muss","soll","kann"], answer: 0, explain: "'Möchten' (would like to) expresses a desire or wish, which fits the context of wanting an ice cream if the weather is nice. This is a common modal-like verb.", language: "de", level: "A2" },
  { id: "q-de-a2-gemini-20-mr5o6i9y", question: "Deine Katze ist ___ als meine.", options: ["klein","kleiner","kleinste","am kleinsten"], answer: 1, explain: "The comparative form of 'klein' (small) is 'kleiner'. It is used with 'als' (than) to compare the size of two cats.", language: "de", level: "A2" },
  { id: "q-de-b1-gemini-1-mr5o6ud9", question: "Das ist der Mann, ___ ich gestern im Park getroffen habe.", options: ["den","dem","der","dessen"], answer: 0, explain: "The relative pronoun must be in the accusative case because 'treffen' (to meet) takes a direct object. 'Mann' is masculine, so 'den' is the correct form.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-2-mr5o6ud9", question: "Als Kind ___ ich oft stundenlang im Garten gespielt.", options: ["habe","hatte","bin","war"], answer: 0, explain: "For a past habit described with 'Als Kind', we use Perfekt (present perfect): 'habe ... gespielt'. 'hatte ... gespielt' would be Plusquamperfekt (past perfect), which requires another past reference point — not the case here.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-3-mr5o6ud9", question: "Die neuen Regeln ___ vom Vorstand noch diskutiert.", options: ["werden","sind","haben","müssen"], answer: 0, explain: "This sentence uses the present passive voice. The auxiliary verb for the passive voice in German is 'werden', conjugated according to the subject ('die Regeln' is plural).", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-4-mr5o6ud9", question: "Wenn ich mehr Zeit ___, würde ich dich besuchen.", options: ["hätte","hatte","habe","bin"], answer: 0, explain: "This is a conditional sentence (Konditional II) expressing an unreal situation. For 'haben', the Konjunktiv II form is 'hätte'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-5-mr5o6ud9", question: "Er sagte, er ___ müde.", options: ["sei","ist","war","würde sein"], answer: 0, explain: "This is reported speech. The Konjunktiv I form 'sei' (from 'sein') is used to report a statement indirectly, indicating that the speaker is reporting what someone else said.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-6-mr5o6ud9", question: "Das ist das Buch, ___ ich dir erzählt habe.", options: ["davon","von dem","dessen","worüber"], answer: 1, explain: "'von dem' is the relative pronoun with preposition 'von' for 'erzählen von' (to tell about). 'worüber' would require the verb 'erzählen über', not 'erzählen von'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-7-mr5o6ud9", question: "Wir ___ gestern Abend lange im Café gesessen.", options: ["haben","sind","waren","hatten"], answer: 0, explain: "The verb 'sitzen' (to sit) forms its Perfekt with 'haben' because it describes a state, not a change of location or state.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-8-mr5o6ud9", question: "Das alte Haus ___ letztes Jahr abgerissen.", options: ["wurde","war","hat","ist"], answer: 0, explain: "This sentence is in the past passive voice (Präteritum Passiv). The auxiliary verb 'werden' is conjugated in the Präteritum, which is 'wurde'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-9-mr5o6ud9", question: "Wenn das Wetter gut ___, gehen wir spazieren.", options: ["ist","wäre","war","würde sein"], answer: 0, explain: "This is a conditional sentence (Konditional I) expressing a real or probable condition. The present tense ('ist') is used in the 'wenn'-clause.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-10-mr5o6ud9", question: "Sie fragte, ob er ihr helfen ___.", options: ["könne","kann","konnte","können"], answer: 0, explain: "In reported speech, modal verbs also take the Konjunktiv I form. The Konjunktiv I of 'kann' (can) is 'könne'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-11-mr5o6ud9", question: "Das ist die Frau, ___ Auto kaputt ist.", options: ["deren","die","der","dessen"], answer: 0, explain: "This is a relative clause using the genitive case to show possession. 'Frau' is feminine, so the genitive relative pronoun is 'deren'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-12-mr5o6ud9", question: "Letzten Monat ___ ich einen interessanten Artikel gelesen.", options: ["habe","bin","war","hatte"], answer: 0, explain: "The verb 'lesen' (to read) forms its Perfekt with 'haben'. The Perfekt is typically used for completed actions in the past in spoken German.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-13-mr5o6ud9", question: "Die Aufgabe ___ bis morgen erledigt werden.", options: ["muss","wird","kann","ist"], answer: 0, explain: "This sentence uses a modal verb ('muss') in combination with the passive voice. The structure is 'Modalverb + Partizip II + werden'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-14-mr5o6ud9", question: "Wenn ich du ___, würde ich sofort kündigen.", options: ["wäre","bin","war","hätte"], answer: 0, explain: "This is a conditional sentence (Konditional II) for an unreal situation. For 'sein', the Konjunktiv II form is 'wäre'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-15-mr5o6ud9", question: "Er fragte, wie spät es ___.", options: ["sei","ist","war","wäre"], answer: 0, explain: "This is reported speech for a question. The verb 'sein' is put into the Konjunktiv I form, 'sei', to indicate indirect speech.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-16-mr5o6ud9", question: "Die Leute, ___ wir geholfen haben, waren sehr dankbar.", options: ["denen","die","der","den"], answer: 0, explain: "The verb 'helfen' (to help) takes the dative case. 'Leute' is plural, so the dative plural relative pronoun is 'denen'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-17-mr5o6ud9", question: "Sie ___ letztes Wochenende in die Berge gefahren.", options: ["ist","hat","war","fährt"], answer: 0, explain: "Verbs of motion or change of state, like 'fahren' (to drive/go), form their Perfekt with the auxiliary verb 'sein', conjugated here as 'ist'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-18-mr5o6ud9", question: "Das Projekt ___ schon vor einer Woche abgeschlossen worden.", options: ["ist","wurde","hat","war"], answer: 0, explain: "This is the passive voice in the present perfect. It is formed with 'sein' (conjugated as 'ist'), the past participle ('abgeschlossen'), and 'worden'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-19-mr5o6ud9", question: "Wenn er ehrlich ___, würden wir ihm glauben.", options: ["wäre","ist","war","hatte"], answer: 0, explain: "This is a conditional sentence (Konditional II) expressing an unreal condition. The Konjunktiv II form of 'sein' is 'wäre'.", language: "de", level: "B1" },
  { id: "q-de-b1-gemini-20-mr5o6ud9", question: "Der Lehrer bat die Schüler, dass sie leise ___.", options: ["seien","sind","waren","würden sein"], answer: 0, explain: "This is reported speech, expressing a request or command indirectly. The verb 'sein' is used in the Konjunktiv I form 'seien' for the plural subject 'Schüler'.", language: "de", level: "B1" },
  // ── en (50 items) ──
  { id: "q-en-a1-gemini-1-mr5nq5rz", question: "She ___ from Spain.", options: ["am","are","is","be"], answer: 2, explain: "The verb 'to be' changes form depending on the subject. For 'she', 'he', and 'it', we use 'is'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-2-mr5nq5rz", question: "They ___ coffee every morning.", options: ["drink","drinks","drinking","drank"], answer: 0, explain: "For plural subjects like 'they' in the simple present tense, the verb does not add an 's'. We use the base form 'drink'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-3-mr5nq5rz", question: "I have ___ cat.", options: ["an","the","a","some"], answer: 2, explain: "'A' is used before singular nouns that start with a consonant sound. 'Cat' starts with a 'c' sound.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-4-mr5nq5rz", question: "We ___ to the park on weekends.", options: ["goes","go","going","went"], answer: 1, explain: "For subjects 'we', 'you', 'they', and 'I' in the simple present tense, the verb 'go' does not change form. 'Goes' is for 'he/she/it'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-5-mr5nq5rz", question: "He ___ a new car.", options: ["have","has","having","haves"], answer: 1, explain: "The verb 'to have' changes form for third-person singular subjects. For 'he', 'she', and 'it', we use 'has'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-6-mr5nq5rz", question: "There are many ___ in the garden.", options: ["flower","flowers","flower's","flowering"], answer: 1, explain: "To make a noun plural in English, we usually add '-s' to the end. So, 'flower' becomes 'flowers'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-7-mr5nq5rz", question: "My brother ___ in London.", options: ["live","lives","living","lived"], answer: 1, explain: "For third-person singular subjects like 'my brother' (which is 'he'), we add an '-s' to the verb in the simple present tense.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-8-mr5nq5rz", question: "She works ___ the front desk ___ a hospital.", options: ["at","in","on","with"], answer: 0, explain: "We use 'at' for a specific point or position. 'At the front desk' refers to a specific workstation, while 'in a hospital' describes the broader workplace.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-9-mr5nq5rz", question: "This is ___ old book.", options: ["a","the","an","some"], answer: 2, explain: "'An' is used before singular nouns that start with a vowel sound. 'Old' starts with an 'o' sound.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-10-mr5nq5rz", question: "We ___ happy to see you.", options: ["am","is","are","be"], answer: 2, explain: "For the subject 'we', the correct form of the verb 'to be' is 'are'. 'Am' is for 'I' and 'is' is for 'he/she/it'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-11-mr5nq5rz", question: "My parents ___ two children.", options: ["has","have","having","haves"], answer: 1, explain: "'My parents' is a plural subject (they), so we use the base form 'have'. 'Has' is for singular subjects like 'he' or 'she'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-12-mr5nq5rz", question: "I usually ___ up early.", options: ["gets","get","getting","got"], answer: 1, explain: "For the subject 'I' in the simple present tense, the verb does not add an 's'. We use the base form 'get'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-13-mr5nq5rz", question: "Are these your ___?", options: ["key","keys","key's","keyes"], answer: 1, explain: "When asking about multiple items, we use the plural form of the noun. The plural of 'key' is 'keys'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-14-mr5nq5rz", question: "He ___ a student.", options: ["am","are","is","be"], answer: 2, explain: "For the subject 'he', the correct form of the verb 'to be' in the present tense is 'is'. 'Am' is for 'I' and 'are' is for 'you/we/they'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-15-mr5nq5rz", question: "They ___ TV in the evening.", options: ["watches","watch","watching","watched"], answer: 1, explain: "For plural subjects like 'they' in the simple present tense, the verb does not add '-es'. We use the base form 'watch'.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-16-mr5nq5rz", question: "The book is ___ the table.", options: ["in","at","on","with"], answer: 2, explain: "We use the preposition 'on' to describe something that is physically touching and supported by a surface, like a book on a table.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-17-mr5nq5rz", question: "Do you like ___ dogs?", options: ["a","an","the","no article"], answer: 3, explain: "Plural countable nouns like 'dogs' used in a general sense take no article (zero article). 'A' and 'an' are singular only; 'the' would refer to specific dogs, not dogs in general.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-18-mr5nq5rz", question: "My sister ___ to school every day.", options: ["go","goes","going","went"], answer: 1, explain: "'My sister' is a third-person singular subject (she), so the verb 'go' changes to 'goes' in the simple present tense.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-19-mr5nq5rz", question: "I'll meet you ___ the library entrance at 5pm.", options: ["at","in","on","to"], answer: 0, explain: "We use 'at' for a specific point or meeting place. 'At the library entrance' refers to a precise location, while 'in' would describe being inside the building generally.", language: "en", level: "A1" },
  { id: "q-en-a1-gemini-20-mr5nq5rz", question: "How many ___ do you have?", options: ["child","children","childs","child's"], answer: 1, explain: "'Children' is the irregular plural form of the noun 'child'. It does not end in '-s'.", language: "en", level: "A1" },
  { id: "q-en-a2-gemini-1-mqsam0dy", question: "I ___ to Paris last year.", options: ["have been","went","go","gone"], answer: 1, explain: "We use the past simple tense for actions that happened at a specific time in the past, indicated here by 'last year'.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-2-mqsam0dy", question: "As your teacher, I advise that you ___ study hard to pass the exam.", options: ["can","must","should","will"], answer: 2, explain: "As your teacher, I advise that you ___ study hard to pass the exam.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-3-mqsam0dy", question: "This book is ___ interesting than the last one.", options: ["more","most","many","much"], answer: 0, explain: "To form the comparative of long adjectives like 'interesting', we use 'more' before the adjective. 'Than' is used to compare two things.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-4-mqsam0dy", question: "She was late ___ the bus broke down.", options: ["but","and","because","so"], answer: 2, explain: "'Because' is a conjunction used to show the reason for something. The bus breaking down is the reason she was late.", language: "en", level: "A2" },
  { id: "q-en-a2-gemini-5-mqsam0dy", question: "Have you ever ___ sushi?", options: ["ate","eat","eaten","eating"], answer: 2, explain: "For the present perfect tense, we use 'have/has' followed by the past participle of the verb. The past participle of 'eat' is 'eaten'.", language: "en", level: "A2" },
  { id: "q-en-b1-gemini-1-mr5nri10", question: "I ___ to London three times this year.", options: ["went","have been","go","was going"], answer: 1, explain: "We use 'have been to' for visited places (experience). 'Have gone to' means the person is still there. With 'I' as subject describing experiences, 'have been to' is correct.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-2-mr5nri10", question: "The new bridge ___ last year.", options: ["built","was built","is building","has built"], answer: 1, explain: "The passive voice is used when the action is more important than the doer, or the doer is unknown. Since the bridge cannot build itself and the action happened in the past ('last year'), the past simple passive 'was built' is correct.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-3-mr5nri10", question: "If I ___ more time, I would learn to play the guitar.", options: ["had","have","will have","would have"], answer: 0, explain: "The second conditional is used for hypothetical situations in the present or future. It uses the past simple in the 'if' clause and 'would + base verb' in the main clause.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-4-mr5nri10", question: "She said that she ___ her keys the day before.", options: ["lost","had lost","has lost","loses"], answer: 1, explain: "When reporting a past simple statement, we usually shift the tense back to the past perfect. 'Yesterday' also changes to 'the day before' in reported speech.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-5-mr5nri10", question: "That's the house ___ I grew up.", options: ["which","who","where","what"], answer: 2, explain: "We use 'where' as a relative pronoun to refer to a place. In this sentence, 'where' introduces a clause that describes the house as the place of growing up.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-6-mr5nri10", question: "My grandparents ___ in this village all their lives.", options: ["lived","have lived","are living","live"], answer: 1, explain: "We use the present perfect to describe an action or state that started in the past and continues up to the present. 'All their lives' indicates a duration that is still ongoing.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-7-mr5nri10", question: "If you study hard, you ___ the exam.", options: ["pass","will pass","passed","would pass"], answer: 1, explain: "The first conditional is used for real or possible situations in the future. It uses the present simple in the 'if' clause and 'will + base verb' in the main clause.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-8-mr5nri10", question: "The email ___ to everyone in the office this morning.", options: ["sent","was sent","has sent","is sending"], answer: 1, explain: "Since the email cannot send itself and the action occurred at a specific past time ('this morning'), the past simple passive 'was sent' is appropriate.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-9-mr5nri10", question: "He asked me ___ I was busy.", options: ["that","if","what","where"], answer: 1, explain: "When reporting a yes/no question, we use 'if' or 'whether' to introduce the reported question. The word order changes from question form to statement form.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-10-mr5nri10", question: "I met a woman ___ brother is a famous actor.", options: ["who","which","whose","that"], answer: 2, explain: "We use 'whose' to show possession or relationship. It means 'of whom' or 'of which' and is used before a noun.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-11-mr5nri10", question: "I ___ my phone when I was walking home yesterday.", options: ["lost","have lost","lose","am losing"], answer: 0, explain: "We use the past simple for actions that were completed at a specific time in the past. 'Yesterday' specifies when the action happened.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-12-mr5nri10", question: "If I ___ you, I would accept the offer.", options: ["was","am","were","had been"], answer: 2, explain: "In second conditional (unreal present), the 'be' verb traditionally takes 'were' for all subjects. 'If I were you' is the fixed expression for giving advice.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-13-mr5nri10", question: "The new stadium ___ by a German company.", options: ["design","is designed","designs","has designed"], answer: 1, explain: "The present simple passive 'is designed' is used to describe a general truth, a regular action, or a characteristic of something. Here, it describes the origin of the design.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-14-mr5nri10", question: "They told us that they ___ to visit us soon.", options: ["come","are coming","were coming","came"], answer: 2, explain: "When reporting a statement in the present continuous, the tense usually shifts back to the past continuous in reported speech.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-15-mr5nri10", question: "Do you know the woman ___ lives next door?", options: ["which","whose","who","where"], answer: 2, explain: "We use 'who' as a relative pronoun to refer to people, especially when the pronoun is the subject of the relative clause.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-16-mr5nri10", question: "I ___ never ___ such a beautiful sunset before.", options: ["saw / have","have / seen","did / see","had / seen"], answer: 1, explain: "We use the present perfect with 'never' to talk about experiences we have not had up to the present moment.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-17-mr5nri10", question: "We ___ late if we don't hurry.", options: ["are","will be","would be","were"], answer: 1, explain: "This is a first conditional sentence, predicting a likely outcome in the future if a certain condition is not met. It uses 'will + base verb' in the main clause.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-18-mr5nri10", question: "English ___ spoken in many countries around the world.", options: ["is","has","was","will"], answer: 0, explain: "The verb 'to be' is essential for forming the passive voice. Since this is a general fact, the present simple passive 'is spoken' is correct.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-19-mr5nri10", question: "He said he ___ finished his homework.", options: ["has","had","will have","is"], answer: 1, explain: "When reporting a statement in the present perfect, the tense usually shifts back to the past perfect in reported speech.", language: "en", level: "B1" },
  { id: "q-en-b1-gemini-20-mr5nri10", question: "The book ___ you lent me was very interesting.", options: ["who","where","which","whose"], answer: 2, explain: "We use 'which' (or 'that') as a relative pronoun to refer to things or animals. Here, it refers to 'the book'.", language: "en", level: "B1" },
  { id: "q-en-b2-gemini-1-mqsamm44", question: "If I had studied harder in college, I ___ a more fulfilling career now.", options: ["would have had","would have","would be having","had had"], answer: 1, explain: "This is a mixed conditional: past unreal condition (had studied) + present unreal result. The present result uses 'would + base verb'. 'Would have a career' is the state; 'would be having' (progressive) is unnatural for stative 'have'.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-2-mqsamm44", question: "It is essential that every student ___ their assignment on time.", options: ["submits","submit","submitted","will submit"], answer: 1, explain: "The subjunctive mood is used after expressions of necessity, importance, or urgency, such as 'It is essential that...'. In this structure, the verb takes its base form, regardless of the subject's number.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-3-mqsamm44", question: "The new policy ___ to significantly improve employee morale.", options: ["is expected","expects","has expected","will expect"], answer: 0, explain: "This sentence uses an advanced passive construction with a reporting verb. When the subject of the main clause is the entity being reported on, the passive voice is typically used, for example, 'The policy is expected to...'", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-4-mqsamm44", question: "___ she wanted for her birthday was a new camera.", options: ["That","What","Which","It"], answer: 1, explain: "This is a 'what' cleft sentence, used to emphasize a particular piece of information. 'What' acts as a pronoun meaning 'the thing that'.", language: "en", level: "B2" },
  { id: "q-en-b2-gemini-5-mqsamm44", question: "She didn't answer her phone; she ___ asleep.", options: ["must have been","should be","might be","had to be"], answer: 0, explain: "'Must have been' is used to express a strong deduction or certainty about a past event, based on available evidence. In this case, not answering the phone leads to the strong conclusion that she was asleep.", language: "en", level: "B2" },
  // ── es (80 items) ──
  { id: "q-es-a1-gemini-1-mr5o1fdy", question: "Yo ___ un estudiante.", options: ["soy","eres","es","somos"], answer: 0, explain: "\"Soy\" is the correct conjugation of \"ser\" (to be) for the first person singular subject \"Yo\" (I). \"Ser\" is used for permanent characteristics like professions.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-2-mr5o1fdy", question: "¿Cómo ___ tú?", options: ["estoy","estás","está","estamos"], answer: 1, explain: "\"Estás\" is the correct conjugation of \"estar\" (to be) for the second person singular subject \"Tú\" (you) when asking about well-being or temporary states.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-3-mr5o1fdy", question: "Nosotros ___ un coche nuevo.", options: ["tengo","tienes","tiene","tenemos"], answer: 3, explain: "\"Tenemos\" is the correct conjugation of \"tener\" (to have) for the first person plural subject \"Nosotros\" (we).", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-4-mr5o1fdy", question: "Ellos ___ al cine los sábados.", options: ["voy","vas","va","van"], answer: 3, explain: "\"Van\" is the correct conjugation of \"ir\" (to go) for the third person plural subject \"Ellos\" (they).", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-5-mr5o1fdy", question: "___ sol es muy brillante hoy.", options: ["La","El","Los","Las"], answer: 1, explain: "\"El\" is the definite article used for singular masculine nouns like \"sol\" (sun). Articles must match the gender and number of the noun.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-6-mr5o1fdy", question: "Me gusta ___ música clásica.", options: ["El","Los","La","Las"], answer: 2, explain: "\"La\" is the definite article used for singular feminine nouns like \"música\" (music). Articles must match the gender and number of the noun.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-7-mr5o1fdy", question: "___ niños juegan en el parque.", options: ["El","La","Los","Las"], answer: 2, explain: "\"Los\" is the definite article used for plural masculine nouns like \"niños\" (children). Articles must match the gender and number of the noun.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-8-mr5o1fdy", question: "Ella compra ___ flores.", options: ["El","La","Los","Las"], answer: 3, explain: "\"Las\" is the definite article used for plural feminine nouns like \"flores\" (flowers). Articles must match the gender and number of the noun.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-9-mr5o1fdy", question: "Necesito ___ bolígrafo para escribir.", options: ["una","unos","un","unas"], answer: 2, explain: "\"Un\" is the indefinite article used for singular masculine nouns like \"bolígrafo\" (pen). Indefinite articles mean 'a' or 'an'.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-10-mr5o1fdy", question: "Hay ___ silla en la habitación.", options: ["un","unos","una","unas"], answer: 2, explain: "\"Una\" is the indefinite article used for singular feminine nouns like \"silla\" (chair). Indefinite articles mean 'a' or 'an'.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-11-mr5o1fdy", question: "Yo ___ en una oficina grande.", options: ["trabajo","trabajas","trabaja","trabajamos"], answer: 0, explain: "\"Trabajo\" is the correct conjugation of the regular -AR verb \"trabajar\" (to work) for the first person singular subject \"Yo\" (I).", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-12-mr5o1fdy", question: "¿Qué ___ tú para el desayuno?", options: ["como","comes","come","comemos"], answer: 1, explain: "\"Comes\" is the correct conjugation of the regular -ER verb \"comer\" (to eat) for the second person singular subject \"Tú\" (you).", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-13-mr5o1fdy", question: "Ella ___ una carta a su abuela.", options: ["escribo","escribes","escribe","escribimos"], answer: 2, explain: "\"Escribe\" is the correct conjugation of the regular -IR verb \"escribir\" (to write) for the third person singular subject \"Ella\" (she).", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-14-mr5o1fdy", question: "Este es el libro ___ mi amigo.", options: ["a","en","de","con"], answer: 2, explain: "\"De\" is used to indicate possession or origin, meaning \"of\" or \"from.\" Here, it shows that the book belongs to the friend.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-15-mr5o1fdy", question: "Nosotros vamos ___ la escuela.", options: ["de","en","a","con"], answer: 2, explain: "\"A\" is used to indicate direction or destination, meaning \"to.\" After \"ir\" (to go), it often precedes the destination.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-16-mr5o1fdy", question: "Mis padres están ___ casa.", options: ["a","en","de","con"], answer: 1, explain: "We use 'en' for locations. Here, it means 'in' or 'at' when talking about being at someone's house: 'en casa de Juan' = 'at Juan's house'.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-17-mr5o1fdy", question: "¿Quieres ir al cine ___ nosotros?", options: ["a","en","de","con"], answer: 3, explain: "\"Con\" is used to indicate accompaniment, meaning \"with.\" It shows that you would go with us.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-18-mr5o1fdy", question: "La flor es muy ___.", options: ["bonita","bonito","bonitos","bonitas"], answer: 0, explain: "Adjectives must agree in gender and number with the noun they describe. \"Flor\" is singular and feminine, so the adjective must also be singular and feminine (\"bonita\").", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-19-mr5o1fdy", question: "Los estudiantes son muy ___.", options: ["inteligente","inteligentes","inteligentas","inteligentos"], answer: 1, explain: "Adjectives must agree in gender and number with the noun they describe. \"Estudiantes\" is plural, so the adjective \"inteligente\" becomes \"inteligentes\" in the plural.", language: "es", level: "A1" },
  { id: "q-es-a1-gemini-20-mr5o1fdy", question: "Mis amigos ___ agua después de correr.", options: ["bebo","bebes","bebe","beben"], answer: 3, explain: "\"Beben\" is the correct conjugation of the regular -ER verb \"beber\" (to drink) for the third person plural subject \"Mis amigos\" (my friends).", language: "es", level: "A1" },
  { id: "q-es-a2-gemini-1-mr5o24l2", question: "Ayer ___ al cine con mis amigos.", options: ["he ido","fui","iba","iré"], answer: 1, explain: "We use the preterite tense (past simple) for actions completed at a specific point in the past, like 'yesterday'.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-2-mr5o24l2", question: "¿___ hablar inglés y francés?", options: ["Puedes","Debes","Tienes que","Podrías"], answer: 0, explain: "\"Poder\" is used to express ability or capability, similar to \"can\" in English.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-3-mr5o24l2", question: "Mi casa es ___ grande ___ la tuya.", options: ["más...que","tan...como","menos...que","tanto...como"], answer: 0, explain: "To form a comparative meaning \"more...than,\" we use the structure \"más + adjective/adverb + que.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-4-mr5o24l2", question: "Quería ir al concierto, ___ no tenía dinero.", options: ["pero","y","o","porque"], answer: 0, explain: "\"Pero\" is used to introduce a contrast or an opposing idea, similar to \"but\" in English.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-5-mr5o24l2", question: "___ esta semana al gimnasio dos veces.", options: ["He ido","Fui","Iré","Iba"], answer: 0, explain: "The present perfect is used for actions that happened in a period of time that is not yet finished, such as \"this week.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-6-mr5o24l2", question: "___ estudiar más para el examen.", options: ["Podrías","Tienes que","Debes","Puedes"], answer: 2, explain: "\"Deber\" expresses an obligation or recommendation, similar to \"should\" or \"ought to\" in English.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-7-mr5o24l2", question: "Ella es ___ alta ___ su hermano.", options: ["más...que","menos...que","tan...como","mejor...que"], answer: 2, explain: "To express equality in comparison (\"as...as\"), we use the structure \"tan + adjective/adverb + como.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-8-mr5o24l2", question: "No fui a la fiesta ___ estaba enfermo.", options: ["y","pero","o","porque"], answer: 3, explain: "\"Porque\" is used to give a reason or explanation, equivalent to \"because\" in English.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-9-mr5o24l2", question: "¿Alguna vez ___ paella?", options: ["comiste","has comido","comías","comerás"], answer: 1, explain: "The present perfect is used with expressions like \"alguna vez\" (ever) to ask about experiences in an indefinite past.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-10-mr5o24l2", question: "___ estudiar para el examen mañana.", options: ["Tengo que","Puedo","Debo","Debería"], answer: 0, explain: "\"Tener que\" expresses a strong obligation or necessity, meaning \"to have to\" or \"must.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-11-mr5o24l2", question: "Su coche es ___ el mío.", options: ["más bueno que","tan bueno como","mejor que","peor que"], answer: 2, explain: "\"Mejor que\" is the irregular comparative form for \"better than\" and is used instead of \"más bueno que.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-12-mr5o24l2", question: "Compramos pan ___ leche en el supermercado.", options: ["e","o","pero","y"], answer: 3, explain: "\"Y\" is used to connect two words or phrases, meaning \"and.\" It changes to \"e\" before words starting with \"i\" or \"hi.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-13-mr5o24l2", question: "El año pasado ___ a España de vacaciones.", options: ["he ido","fui","iba","iré"], answer: 1, explain: "We use the preterite tense for actions completed at a specific point in the past, such as \"last year.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-14-mr5o24l2", question: "No ___ venir a la reunión hoy.", options: ["deberías","puedo","tienes que","puedes"], answer: 1, explain: "\"Poder\" can also be used in negative sentences to express inability or lack of permission, meaning \"cannot.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-15-mr5o24l2", question: "Este ejercicio es más fácil, es ___ difícil ___ el anterior.", options: ["más...que","tan...como","menos...que","mucho...que"], answer: 2, explain: "Since the exercise is 'más fácil' (easier), it is 'menos difícil' (less difficult) than the previous one. 'menos...que' is the comparative of inferiority.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-16-mr5o24l2", question: "Mi hermano es inteligente ___ imaginativo.", options: ["y","o","pero","e"], answer: 3, explain: "\"Y\" changes to \"e\" when the following word starts with the sound \"i\" (e.g., \"inteligente\") to avoid phonetic clash.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-17-mr5o24l2", question: "Todavía no ___ mis deberes.", options: ["hice","he hecho","hacía","hago"], answer: 1, explain: "\"Todavía no\" (not yet) typically triggers the use of the present perfect, indicating an action that has not happened up to the present moment.", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-18-mr5o24l2", question: "No ___ hablar tan alto en la biblioteca.", options: ["puedes","tienes que","debes","podrías"], answer: 2, explain: "\"No deber\" expresses a recommendation against doing something or a mild prohibition, meaning \"shouldn't.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-19-mr5o24l2", question: "La película fue ___ el libro.", options: ["más mala que","tan mala como","peor que","mejor que"], answer: 2, explain: "\"Peor que\" is the irregular comparative form for \"worse than\" and is used instead of \"más mala que.\"", language: "es", level: "A2" },
  { id: "q-es-a2-gemini-20-mr5o24l2", question: "Me encanta la música clásica, ___ mi hermana prefiere el pop.", options: ["porque","y","o","pero"], answer: 3, explain: "\"Pero\" is used to show a contrast between two ideas or statements.", language: "es", level: "A2" },
  { id: "q-es-b1-gemini-1-mr5o2udn", question: "Esta semana ___ dos libros muy interesantes.", options: ["leí","he leído","leeré","leía"], answer: 1, explain: "The present perfect (he leído) is used for actions completed within a time period that is still ongoing (esta semana).", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-2-mr5o2udn", question: "Ayer ___ al cine con mis amigos y vimos una película genial.", options: ["fui","he ido","iba","vaya"], answer: 0, explain: "The past simple (fui) is used for actions completed in a definite past time (ayer) that is now finished.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-3-mr5o2udn", question: "Todavía no ___ a la nueva exposición de arte.", options: ["fui","he ido","iba","voy"], answer: 1, explain: "The present perfect (he ido) is used with 'todavía no' to express an action that has not happened up to the present moment.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-4-mr5o2udn", question: "Cuando era niño, ___ mucho chocolate, pero este año solo ___ un poco.", options: ["comía / he comido","he comido / comí","comí / comía","comeré / comí"], answer: 0, explain: "'Comía' describes a habitual action in the past, while 'he comido' refers to an action within the current year, which is an ongoing period.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-5-mr5o2udn", question: "No puedo abrir la puerta porque ___ las llaves.", options: ["perdí","he perdido","pierdo","perderé"], answer: 1, explain: "The present perfect (he perdido) is used to describe a past action that has a direct consequence or relevance in the present.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-6-mr5o2udn", question: "Si ___ tiempo mañana, iremos al parque.", options: ["tuviera","tendría","tengo","tuve"], answer: 2, explain: "The first conditional uses the present indicative (tengo) after 'si' for a real or very probable condition, followed by the future tense in the main clause.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-7-mr5o2udn", question: "Si yo ___ la lotería, viajaría por todo el mundo.", options: ["ganaba","ganaría","ganara","gano"], answer: 2, explain: "The second conditional uses the imperfect subjunctive (ganara) after 'si' to express a hypothetical or unlikely condition, followed by the conditional tense in the main clause.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-8-mr5o2udn", question: "Si no ___ tus deberes, no podrás salir a jugar.", options: ["hicieras","hiciste","harías","haces"], answer: 3, explain: "This is a first conditional sentence. The present indicative (haces) is used after 'si' for a real condition, and the main clause uses 'poder' in the future.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-9-mr5o2udn", question: "Si yo ___ tú, estudiaría más para el examen.", options: ["soy","fuera","era","fui"], answer: 1, explain: "The phrase 'Si yo fuera tú' (If I were you) is a common idiom using the imperfect subjunctive to give advice or make a suggestion.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-10-mr5o2udn", question: "Te ayudaría con tu proyecto si ___ más tiempo libre.", options: ["tuve","tendría","tengo","tuviera"], answer: 3, explain: "The conditional tense in the main clause ('ayudaría') indicates a hypothetical situation, requiring the imperfect subjunctive ('tuviera') in the 'si' clause.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-11-mr5o2udn", question: "Ella dijo: 'Estoy muy cansada'. Ella dijo que ___ muy cansada.", options: ["está","estaría","estaba","estuvo"], answer: 2, explain: "When reporting a statement, the present tense in direct speech (estoy) usually shifts to the imperfect tense in reported speech (estaba).", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-12-mr5o2udn", question: "Él preguntó: '¿Dónde está el museo?' Él preguntó dónde ___ el museo.", options: ["está","estaría","estuvo","estaba"], answer: 3, explain: "When reporting a question, the tense typically shifts from present (está) to imperfect (estaba), and the question mark is removed.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-13-mr5o2udn", question: "La profesora nos dijo: 'Hagan sus tareas'. La profesora nos dijo que ___ nuestras tareas.", options: ["hacemos","hagamos","haríamos","hiciéramos"], answer: 3, explain: "When reporting a command, the imperative (Hagan) usually transforms into the imperfect subjunctive (hiciéramos) introduced by 'que'.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-14-mr5o2udn", question: "Ellos dijeron: 'Mañana iremos a la playa'. Ellos dijeron que al día siguiente ___ a la playa.", options: ["irían","fueron","irán","iban"], answer: 0, explain: "When reporting a future action, the future tense (iremos) in direct speech generally changes to the conditional tense (irían) in reported speech, and 'mañana' becomes 'al día siguiente'.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-15-mr5o2udn", question: "El libro ___ me recomendaste es muy interesante.", options: ["cual","quien","que","cuyo"], answer: 2, explain: "'Que' is the most common relative pronoun, used for both people and things, and can function as a subject or object.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-16-mr5o2udn", question: "Mi hermana, ___ vive en Madrid, viene a visitarme.", options: ["que","la cual","cuyo","quien"], answer: 3, explain: "'Quien' (or 'quienes' for plural) is used for people, especially in non-defining clauses (set off by commas) or after prepositions.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-17-mr5o2udn", question: "Conocí a un hombre ___ hermano es un famoso escritor.", options: ["que","quien","cuyo","el cual"], answer: 2, explain: "'Cuyo' (whose) is a possessive relative pronoun that agrees in gender and number with the noun it modifies (hermano), not the antecedent (hombre).", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-18-mr5o2udn", question: "La novela ___ por un autor muy conocido.", options: ["escribió","ha escrito","se escribe","fue escrita"], answer: 3, explain: "The passive voice is formed with 'ser' + past participle. 'Fue escrita' (was written) indicates that the novel received the action.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-19-mr5o2udn", question: "En esta tienda ___ ropa de segunda mano.", options: ["se vende","es vendida","vende","está vendiendo"], answer: 0, explain: "The passive reflexive 'se' is commonly used to express general or impersonal actions, indicating that something is done without specifying the agent.", language: "es", level: "B1" },
  { id: "q-es-b1-gemini-20-mr5o2udn", question: "El problema ___ discutido en la reunión de mañana.", options: ["será","está","es","ha sido"], answer: 0, explain: "To form the passive voice in the future, 'ser' is conjugated in the future tense ('será') followed by the past participle ('discutido').", language: "es", level: "B1" },
  { id: "q-es-b2-gemini-1-mr5o3gk5", question: "Si ___ más tiempo, ahora no tendríamos tanta prisa.", options: ["hubiéramos tenido","habíamos tenido","tuviéramos","tendríamos"], answer: 0, explain: "This is a mixed conditional sentence. The \"si\" clause uses the pluperfect subjunctive (\"hubiéramos tenido\") to refer to an unreal condition in the past, and the main clause uses the conditional simple (\"tendríamos\") to refer to a present unreal result.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-2-mr5o3gk5", question: "No se irán de vacaciones ___ el informe.", options: ["hasta que terminan","hasta que terminen","hasta que terminaron","hasta que terminaban"], answer: 1, explain: "The conjunction \"hasta que\" requires the subjunctive when referring to an action that has not yet occurred (future action). Therefore, \"terminen\" (present subjunctive) is the correct form.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-3-mr5o3gk5", question: "En este restaurante ___ platos típicos de la región.", options: ["se sirve","se sirven","se sirvieron","se ha servido"], answer: 1, explain: "The impersonal \"se\" construction with a plural direct object (\"platos típicos\") requires the verb to be in the plural form (\"sirven\"). This construction indicates that typical dishes are served, without specifying who serves them.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-4-mr5o3gk5", question: "___ quien descubrió la verdad, no yo.", options: ["Fue él","Era él","Es él","Ha sido él"], answer: 0, explain: "This is a cleft sentence emphasizing \"él\". The preterite \"fue\" is used here to indicate a completed action in the past, stressing that \"he\" was the one who discovered the truth.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-5-mr5o3gk5", question: "María ___ estar muy cansada después de trabajar todo el día.", options: ["debe de","debe","debería","había de"], answer: 0, explain: "\"Deber de + infinitive\" is used to express probability or conjecture, meaning \"must be\" or \"probably is.\" \"Deber + infinitive\" indicates obligation. In this context, it's a conjecture about Maria's tiredness.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-6-mr5o3gk5", question: "Buscamos a un empleado ___ mucha experiencia en ventas.", options: ["que tiene","que tenga","que tenía","que ha tenido"], answer: 1, explain: "When the antecedent of a relative clause is indefinite or unknown to the speaker (e.g., \"un empleado\" that hasn't been identified), the subjunctive mood is used in the relative clause.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-7-mr5o3gk5", question: "Si ___ más tiempo libre, ayer te habría ayudado con tu proyecto.", options: ["tengo","tuviera","tenía","tenga"], answer: 1, explain: "This is a mixed conditional. The \"si\" clause uses the imperfect subjunctive (\"tuviera\") for a present unreal condition, and the main clause uses the conditional perfect (\"habría ayudado\") for a past unreal result.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-8-mr5o3gk5", question: "La novela ___ por un autor desconocido.", options: ["fue escrita","está escrita","se escribe","ha escrito"], answer: 0, explain: "The passive voice with \"ser + past participle + por\" is used to express an action performed by an agent in the past. \"Fue escrita\" (preterite passive) correctly conveys that the novel was written by someone.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-9-mr5o3gk5", question: "Es importante que nosotros ___ las instrucciones cuidadosamente.", options: ["leemos","leamos","leeremos","leímos"], answer: 1, explain: "Impersonal expressions that convey opinion, necessity, or emotion (like \"Es importante que\") require the subjunctive mood in the subordinate clause. \"Leamos\" is the present subjunctive form for \"nosotros.\"", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-10-mr5o3gk5", question: "Cuando era niño, ___ jugar en el parque hasta tarde.", options: ["solía","podía","quería","debía"], answer: 0, explain: "\"Soler + infinitive\" is used to express habitual actions in the past (or present), meaning \"used to\" or \"would (do something regularly).\" \"Solía\" correctly conveys this past habit.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-11-mr5o3gk5", question: "___ más me gusta de la película es la banda sonora.", options: ["Lo que","El que","La que","Qué"], answer: 0, explain: "\"Lo que\" is used in a cleft sentence to emphasize a concept or idea, meaning \"what\" or \"the thing that.\" Here, it emphasizes \"the thing that I like most.\"", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-12-mr5o3gk5", question: "___ llueva mañana, iremos de picnic.", options: ["Aunque","A pesar de que","Aunque sea que","Si bien"], answer: 0, explain: "\"Aunque\" followed by the subjunctive mood is used to express a concession when there is uncertainty or doubt about the truth of the statement. Here, \"llueva\" (present subjunctive) implies uncertainty about the rain.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-13-mr5o3gk5", question: "Todas las ventanas del edificio ya ___ bien cerradas.", options: ["fueron","estaban","son","están"], answer: 3, explain: "\"Estar + past participle\" describes a resulting state or condition, not the action itself. \"Están cerradas\" correctly indicates that the windows are currently in the state of being closed.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-14-mr5o3gk5", question: "Si no ___ tanto, ahora tendríamos más dinero ahorrado.", options: ["hubiéramos gastado","gastaríamos","gastamos","habíamos gastado"], answer: 0, explain: "This is a mixed conditional. \"Si no hubiéramos gastado\" (pluperfect subjunctive) refers to an unreal past condition, and \"tendríamos\" (conditional simple) refers to an unreal present result.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-15-mr5o3gk5", question: "Te lo digo para que ___ lo que piensas.", options: ["me dices","me digas","me dirás","me decías"], answer: 1, explain: "The conjunction \"para que\" (in order that, so that) always introduces a subordinate clause in the subjunctive mood. \"Me digas\" is the correct present subjunctive form.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-16-mr5o3gk5", question: "Para aprender un idioma nuevo, ___ practicar todos los días.", options: ["hay que","tienes que","debería","puedes"], answer: 0, explain: "\"Hay que + infinitive\" expresses a general, impersonal obligation (\"one must\"). \"Tienes que\" would be specific to \"tú.\" The sentence implies a general truth about language learning.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-17-mr5o3gk5", question: "Dudo que ellos ___ a tiempo para la reunión.", options: ["lleguen","llegan","llegarán","llegaron"], answer: 0, explain: "Verbs and expressions of doubt, denial, or disbelief (like \"dudar que\") require the subjunctive mood in the subordinate clause. \"Lleguen\" is the present subjunctive.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-18-mr5o3gk5", question: "___ me preocupa es su falta de interés.", options: ["Lo que","Qué","Quien","El que"], answer: 0, explain: "\"Lo que\" is used to introduce a noun clause that acts as the subject of the sentence, meaning \"what\" or \"the thing that.\" It emphasizes the specific aspect causing concern.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-19-mr5o3gk5", question: "Las nuevas normas ___ ayer en el parlamento.", options: ["se aprobaron","aprobaban","estaban aprobadas","han aprobado"], answer: 0, explain: "Reflexive passive 'se aprobaron' is the standard way to express passive voice for completed actions in Spanish. 'aprobaban' (imperfect) describes ongoing past, not a completed event; 'estaban aprobadas' is a state, not an action; 'han aprobado' (present perfect) doesn't match 'ayer'.", language: "es", level: "B2" },
  { id: "q-es-b2-gemini-20-mr5o3gk5", question: "Mi hermano ___ cocinar muy bien, pero hoy no puede porque está enfermo.", options: ["sabe","puede","debe","quiere"], answer: 0, explain: "\"Saber + infinitive\" is used to express knowing how to do something (a skill or ability). \"Sabe cocinar\" means he has the skill of cooking, contrasting with \"no puede\" (cannot due to circumstances).", language: "es", level: "B2" },
  // ── fr (80 items) ──
  { id: "q-fr-a1-gemini-1-mr5o43p1", question: "Tu ___ étudiant.", options: ["est","sont","es","êtes"], answer: 2, explain: "'Être' is an irregular verb. 'Tu es' is the correct conjugation for the second person singular.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-2-mr5o43p1", question: "J'___ un livre intéressant.", options: ["a","as","ont","ai"], answer: 3, explain: "'Avoir' is an irregular verb. 'J'ai' is the correct conjugation for the first person singular.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-3-mr5o43p1", question: "Nous ___ au marché tous les samedis.", options: ["vont","allez","allons","vas"], answer: 2, explain: "'Aller' is an irregular verb. 'Nous allons' is the correct conjugation for the first person plural.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-4-mr5o43p1", question: "Il ___ français très bien.", options: ["parlent","parles","parle","parlons"], answer: 2, explain: "For regular -er verbs, the third person singular (il/elle/on) ends in -e.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-5-mr5o43p1", question: "J'aime ___ chocolat noir.", options: ["la","les","un","le"], answer: 3, explain: "'Chocolat' is a masculine singular noun, so it takes the definite article 'le'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-6-mr5o43p1", question: "Elle mange ___ pomme rouge.", options: ["le","la","les","une"], answer: 1, explain: "'Pomme' is a feminine singular noun, so it takes the definite article 'la'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-7-mr5o43p1", question: "C'est ___ stylo bleu.", options: ["une","des","un","le"], answer: 2, explain: "'Stylo' is a masculine singular noun, so it takes the indefinite article 'un'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-8-mr5o43p1", question: "C'est ___ table petite.", options: ["un","une","des","la"], answer: 1, explain: "'Table' is a feminine singular noun, so it takes the indefinite article 'une'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-9-mr5o43p1", question: "J'ai ___ livres dans ma bibliothèque.", options: ["le","la","des","les"], answer: 3, explain: "'Livres' is a plural noun, so it takes the plural definite article 'les'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-10-mr5o43p1", question: "Il y a ___ étudiants dans la classe aujourd'hui.", options: ["les","un","une","des"], answer: 3, explain: "'Étudiants' is a plural noun, so it takes the plural indefinite article 'des'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-11-mr5o43p1", question: "Je vais ___ Paris la semaine prochaine.", options: ["de","en","sur","à"], answer: 3, explain: "The preposition 'à' is used for cities, indicating direction 'to' or location 'at'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-12-mr5o43p1", question: "C'est le sac ___ mon ami.", options: ["à","sur","de","dans"], answer: 2, explain: "The preposition 'de' is used to indicate possession or origin, similar to 'of' or the possessive 's in English.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-13-mr5o43p1", question: "Le chat dort ___ la boîte en carton.", options: ["sur","sous","à","dans"], answer: 3, explain: "The preposition 'dans' means 'in' or 'inside'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-14-mr5o43p1", question: "Le téléphone est ___ la table basse.", options: ["sous","dans","à","sur"], answer: 3, explain: "The preposition 'sur' means 'on' or 'on top of'.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-15-mr5o43p1", question: "Ce garçon est très ___.", options: ["grande","grands","grand","grandes"], answer: 2, explain: "'Garçon' is masculine singular, so the adjective 'grand' (tall/big) must also be masculine singular.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-16-mr5o43p1", question: "La fille est très ___.", options: ["beau","beaux","belles","belle"], answer: 3, explain: "'Fille' is feminine singular, so the adjective 'belle' (beautiful) must also be feminine singular.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-17-mr5o43p1", question: "Les enfants sont ___ et heureux.", options: ["petit","petite","petites","petits"], answer: 3, explain: "'Enfants' is masculine plural, so the adjective 'petits' (small) must also be masculine plural. Even with mixed gender, masculine plural is used.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-18-mr5o43p1", question: "Les maisons sont ___ et anciennes.", options: ["grand","grande","grands","grandes"], answer: 3, explain: "'Maisons' is feminine plural, so the adjective 'grandes' (big) must also be feminine plural.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-19-mr5o43p1", question: "Nous ___ nos devoirs rapidement.", options: ["finissez","finissent","finis","finissons"], answer: 3, explain: "For regular -ir verbs, the first person plural (nous) ends in -issons.", language: "fr", level: "A1" },
  { id: "q-fr-a1-gemini-20-mr5o43p1", question: "Tu ___ le bus à l'arrêt.", options: ["attend","attendons","attendez","attends"], answer: 3, explain: "For regular -re verbs, the second person singular (tu) ends in -s.", language: "fr", level: "A1" },
  { id: "q-fr-a2-gemini-1-mr5o4lbp", question: "Quand j'___ jeune, je jouais souvent au parc.", options: ["étais","suis","ai été","serais"], answer: 0, explain: "Use the imparfait ('étais') to describe a state or habitual action in the past. 'Quand j'étais jeune' describes a period of being young.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-2-mr5o4lbp", question: "Hier, nous ___ un bon film à la télévision.", options: ["regardions","avons regardé","regardons","regarderai"], answer: 1, explain: "The passé composé ('avons regardé') is used for actions completed at a specific point in the past. 'Hier' indicates a specific past event.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-3-mr5o4lbp", question: "Tu ___ étudier plus si tu veux réussir l'examen.", options: ["peux","dois","veux","sais"], answer: 1, explain: "The verb 'devoir' (dois) indicates an obligation or necessity. Here, it means 'you must' or 'you should' study more.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-4-mr5o4lbp", question: "Pierre est plus grand que moi, il est ___ grand ___ son frère.", options: ["plus...que","moins...que","aussi...que","meilleur...que"], answer: 0, explain: "Comparative of superiority: 'plus...que' = 'more...than'. The context 'Pierre est plus grand' indicates Pierre is taller, so we use 'plus...que' to compare him to his brother.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-5-mr5o4lbp", question: "Elle est fatiguée ___ elle a beaucoup travaillé.", options: ["mais","ou","et","parce que"], answer: 3, explain: "'Parce que' is used to introduce the reason or cause for something. She is tired because she worked a lot.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-6-mr5o4lbp", question: "Je lisais quand le téléphone ___.", options: ["sonnait","a sonné","sonne","sonnera"], answer: 1, explain: "The imparfait ('lisais') describes an ongoing action, while the passé composé ('a sonné') describes a sudden, completed action that interrupted it.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-7-mr5o4lbp", question: "Nous ___ venir à la fête si nous finissons tôt.", options: ["voulons","devons","pouvons","savons"], answer: 2, explain: "'Pouvoir' (pouvons) indicates ability or possibility. Here, it means 'we can' come to the party if they finish early.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-8-mr5o4lbp", question: "La ville est ___ grande ___ la campagne.", options: ["plus...que","moins...que","aussi...que","tellement...que"], answer: 2, explain: "To express 'as...as' in comparisons, use the structure 'aussi...que'. This indicates equality.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-9-mr5o4lbp", question: "Il voulait sortir, ___ il pleuvait très fort.", options: ["et","ou","parce que","mais"], answer: 3, explain: "'Mais' is used to introduce a contrast or opposition. He wanted to go out, but it was raining heavily.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-10-mr5o4lbp", question: "D'abord, il ___ ses clés, puis il ___ la porte.", options: ["prenait / ouvrait","a pris / a ouvert","prend / ouvre","prendra / ouvrira"], answer: 1, explain: "The passé composé ('a pris', 'a ouvert') is used for a series of completed actions in the past. 'D'abord...puis' indicates a sequence.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-11-mr5o4lbp", question: "Je ___ apprendre le français couramment.", options: ["peux","dois","veux","sais"], answer: 2, explain: "'Vouloir' (veux) expresses a desire or wish. Here, it means 'I want' to learn French fluently.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-12-mr5o4lbp", question: "Ce film est ennuyeux, il est ___ amusant ___ l'autre.", options: ["plus...que","moins...que","aussi...que","meilleur...que"], answer: 1, explain: "Since the film is described as 'ennuyeux' (boring), it is 'moins amusant' (less amusing) than the other. 'moins...que' is the comparative of inferiority.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-13-mr5o4lbp", question: "Elle aime le café ___ le chocolat.", options: ["ou","mais","et","parce que"], answer: 2, explain: "'Et' is used to connect two items or ideas, meaning 'and'. It indicates addition.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-14-mr5o4lbp", question: "Chaque été, nous ___ à la mer, mais l'année dernière, nous ___ à la montagne.", options: ["allions / sommes allés","sommes allés / allions","allons / irons","irions / allions"], answer: 0, explain: "'Chaque été' indicates a habitual action in the past, requiring the imparfait ('allions'). 'L'année dernière' indicates a specific completed action, requiring the passé composé ('sommes allés').", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-15-mr5o4lbp", question: "Vous ___ manger des légumes pour être en bonne santé.", options: ["voulez","pouvez","devez","savez"], answer: 2, explain: "'Devoir' (devez) can express advice or a recommendation, meaning 'you should'. It's a mild obligation for well-being.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-16-mr5o4lbp", question: "Mon nouveau téléphone est ___ que l'ancien.", options: ["plus bon","meilleur","plus bien","mieux"], answer: 1, explain: "'Meilleur' is the irregular comparative form of 'bon' (good), meaning 'better'. Do not use 'plus bon'.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-17-mr5o4lbp", question: "Préférez-vous le thé ___ le café ?", options: ["et","mais","ou","parce que"], answer: 2, explain: "'Ou' is used to present a choice between two or more options, meaning 'or'.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-18-mr5o4lbp", question: "Il ___ très froid quand nous ___ la maison.", options: ["faisait / avons quitté","a fait / quittions","faisait / quittions","a fait / avons quitté"], answer: 0, explain: "The imparfait ('faisait') describes the weather condition (a state or description), while the passé composé ('avons quitté') describes a specific completed action.", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-19-mr5o4lbp", question: "Est-ce que je ___ t'aider avec tes devoirs ?", options: ["dois","veux","peux","sais"], answer: 2, explain: "'Pouvoir' (peux) is used to ask for permission or to offer help. Here, it means 'can I help you?'", language: "fr", level: "A2" },
  { id: "q-fr-a2-gemini-20-mr5o4lbp", question: "Sa santé est ___ que l'année dernière.", options: ["plus mal","pire","moins bien","plus mauvais"], answer: 1, explain: "'pire' is the irregular comparative of 'mauvais' and is the standard form for 'worse'. 'plus mauvais' (without gender agreement) is grammatically incorrect; the correct feminine form would be 'plus mauvaise', but 'pire' is preferred in modern French for health and abstract qualities.", language: "fr", level: "A2" },
  { id: "q-fr-b1-gemini-1-mr5o5cvm", question: "Hier, je ___ au marché quand il a commencé à pleuvoir.", options: ["étais","suis allé","allais","irais"], answer: 2, explain: "The imperfect (allais) is used to describe an ongoing action or state in the past that was interrupted by another event (a commencé à pleuvoir) in the passé composé.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-2-mr5o5cvm", question: "Quand elle ___ la porte, elle ___ un bruit étrange.", options: ["ouvrait / a entendu","a ouvert / a entendu","a ouvert / entendait","ouvrait / entendait"], answer: 1, explain: "The passé composé is used for two consecutive, completed actions in the past: first she opened the door, then she heard a strange noise.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-3-mr5o5cvm", question: "Mon grand-père ___ un homme très généreux et il ___ toujours des histoires fascinantes.", options: ["a été / a raconté","était / a raconté","était / racontait","a été / racontait"], answer: 2, explain: "The imperfect (était, racontait) is used for descriptions, characteristics, and habitual actions in the past. Here, it describes his character and a recurring action.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-4-mr5o5cvm", question: "Nous ___ en France pendant trois ans avant de déménager en Allemagne.", options: ["vivions","avons vécu","avons vivant","vivrions"], answer: 1, explain: "The passé composé (avons vécu) is used to express a completed action or a state that lasted for a specific duration in the past, with a clear beginning and end.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-5-mr5o5cvm", question: "Si tu étudies bien, tu ___ tes examens.", options: ["réussissais","réussirais","réussiras","as réussi"], answer: 2, explain: "This is a first conditional sentence. With 'si' + present tense in the first clause, the second clause uses the future simple to express a probable outcome.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-6-mr5o5cvm", question: "Si j'___ assez d'argent, je ferais le tour du monde.", options: ["ai","avais","aurai","aurais"], answer: 1, explain: "This is a second conditional sentence. With 'si' + imperfect in the first clause, the second clause uses the conditional present to express a hypothetical or unlikely situation.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-7-mr5o5cvm", question: "Si elle ne se dépêche pas, elle ___ son train.", options: ["manquerait","manquera","a manqué","manque"], answer: 1, explain: "This is a first conditional sentence expressing a probable future event. The structure is 'si' + present tense, followed by the future simple.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-8-mr5o5cvm", question: "Si tu venais avec nous, tu ___ voir le nouveau film.", options: ["peux","pourras","pourrais","pouvais"], answer: 2, explain: "This is a second conditional sentence. With 'si' + imperfect, the result clause requires the conditional present to describe a hypothetical outcome.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-9-mr5o5cvm", question: "Il a dit: 'Je suis fatigué.' -> Il a dit qu'il ___ fatigué.", options: ["est","était","sera","ait été"], answer: 1, explain: "In reported speech, when the main verb is in the past (a dit), the present tense in the direct speech (suis) changes to the imperfect (était).", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-10-mr5o5cvm", question: "Elle a annoncé: 'Nous partirons demain.' -> Elle a annoncé qu'ils ___ le lendemain.", options: ["partiront","partiraient","sont partis","partaient"], answer: 1, explain: "When reporting speech, the future simple (partirons) changes to the conditional present (partiraient) if the main verb is in the past. 'Demain' also changes to 'le lendemain'.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-11-mr5o5cvm", question: "Il m'a demandé: 'Où vas-tu ?' -> Il m'a demandé où je ___.", options: ["vais","allais","irais","étais allé"], answer: 1, explain: "In reported questions, the tense shifts (present 'vas' to imperfect 'allais') and the subject-verb inversion is removed. The question word 'où' connects the clauses.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-12-mr5o5cvm", question: "Le professeur a dit: 'Faites vos devoirs !' -> Le professeur a dit de ___ leurs devoirs.", options: ["faisiez","faire","font","feraient"], answer: 1, explain: "Commands in reported speech are often transformed using 'de' + infinitive. The verb 'faire' is used in its infinitive form.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-13-mr5o5cvm", question: "Voici l'étudiant ___ a gagné le prix.", options: ["que","dont","où","qui"], answer: 3, explain: "'Qui' is used as a relative pronoun when it functions as the subject of the relative clause. Here, 'qui' refers to 'l'étudiant' and performs the action of winning.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-14-mr5o5cvm", question: "C'est le livre ___ j'ai lu la semaine dernière.", options: ["qui","où","dont","que"], answer: 3, explain: "'Que' is used as a relative pronoun when it functions as the direct object of the relative clause. Here, 'que' refers to 'le livre' which is read by 'je'.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-15-mr5o5cvm", question: "Je me souviens du jour ___ nous nous sommes rencontrés.", options: ["que","qui","dont","où"], answer: 3, explain: "'Où' is used as a relative pronoun to refer to a place or a time. Here, it refers to 'le jour' (time) when the meeting occurred.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-16-mr5o5cvm", question: "C'est l'auteur ___ le nouveau roman est un best-seller.", options: ["que","qui","où","dont"], answer: 3, explain: "'Dont' is used as a relative pronoun to replace 'de' + noun, often indicating possession (whose) or a complement introduced by 'de'. Here, 'le roman de l'auteur' becomes 'l'auteur dont le roman'.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-17-mr5o5cvm", question: "La lettre ___ par la secrétaire.", options: ["a écrit","écrivait","a été écrite","est écrit"], answer: 2, explain: "The passive voice is formed with 'être' + past participle. The past participle ('écrite') must agree in gender and number with the subject ('La lettre' is feminine singular).", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-18-mr5o5cvm", question: "Ces maisons ___ en 1990.", options: ["ont construit","étaient construites","ont été construites","sont construites"], answer: 2, explain: "The passive voice is formed using the verb 'être' in the appropriate tense (here, passé composé 'ont été') followed by the past participle ('construites'), which agrees with the subject 'Ces maisons'.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-19-mr5o5cvm", question: "Le voleur ___ par la police.", options: ["a arrêté","arrêtait","a été arrêté","est arrêtant"], answer: 2, explain: "The passive voice is used to show that the subject (le voleur) receives the action. It is formed with 'être' (a été) and the past participle (arrêté). The agent is introduced by 'par'.", language: "fr", level: "B1" },
  { id: "q-fr-b1-gemini-20-mr5o5cvm", question: "Les fleurs ___ par l'enfant chaque matin.", options: ["seront arrosé","seront arrosés","seront arrosées","seront arrose"], answer: 2, explain: "In the passive voice, the past participle (arrosées) must agree in gender and number with the subject (Les fleurs, which is feminine plural).", language: "fr", level: "B1" },
  { id: "q-fr-b2-gemini-1-mr5o5rye", question: "Si tu avais écouté mes conseils, tu ne ___ pas dans cette situation difficile aujourd'hui.", options: ["serais","aurais été","étais","es"], answer: 0, explain: "This is a mixed conditional sentence. The 'si' clause in the plus-que-parfait (avais écouté) describes a past condition, and the main clause in the conditionnel présent (ne serais pas) describes a present result.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-2-mr5o5rye", question: "Il est impératif que nous ___ une solution avant la fin de la semaine.", options: ["trouvons","trouvions","trouverons","avons trouvé"], answer: 1, explain: "The expression 'il est impératif que' requires the subjunctive mood. Therefore, 'trouvions' (subjunctive present of trouver) is the correct form for 'nous'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-3-mr5o5rye", question: "Le rapport ___ être approuvé par le comité la semaine prochaine.", options: ["doit","devra","doive","faut"], answer: 1, explain: "The future tense 'devra' is required here to indicate a future obligation or necessity for the report to be approved. 'Doit' is present, 'doive' is subjunctive, and 'faut' is impersonal.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-4-mr5o5rye", question: "C'est ___ que nous avons rencontré hier au café.", options: ["lui","ce","il","son"], answer: 0, explain: "This is a cleft sentence used to emphasize the object of the verb. After 'C'est... que', a stressed pronoun like 'lui' (referring to 'him') is used.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-5-mr5o5rye", question: "Malgré la pluie, il ___ courir le marathon.", options: ["a pu","pouvait","aurait pu","puisse"], answer: 0, explain: "The passé composé 'a pu' is used here to express that he succeeded in running the marathon despite the rain, indicating a completed action in the past.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-6-mr5o5rye", question: "J'aurais aimé que tu ___ là pour me soutenir.", options: ["sois","étais","fusses","sois été"], answer: 0, explain: "The expression 'j'aurais aimé que' requires the subjunctive mood for the following clause, referring to a past wish or regret. 'Sois' is the subjunctive present of 'être'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-7-mr5o5rye", question: "On ___ réparer la voiture depuis des semaines, mais on n'a pas eu le temps.", options: ["devait","aurait dû","doit","a dû"], answer: 1, explain: "The conditional past 'aurait dû' expresses an unfulfilled past obligation or something that should have been done but wasn't. It means 'should have'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-8-mr5o5rye", question: "Ce sont les architectes ___ ont conçu ce bâtiment moderne.", options: ["qui","que","dont","où"], answer: 0, explain: "This is a cleft sentence emphasizing the subject. 'Ce sont... qui' is used when emphasizing the subject, which is plural in this case ('les architectes').", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-9-mr5o5rye", question: "Pourvu qu'il ne ___ pas trop froid ce soir!", options: ["fait","fasse","ferait","est fait"], answer: 1, explain: "The expression 'pourvu que' (provided that, let's hope that) always introduces a clause in the subjunctive mood. 'Fasse' is the subjunctive present of 'faire'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-10-mr5o5rye", question: "Le nouveau système de sécurité ___ installé la semaine prochaine.", options: ["va se faire","est en train de","doit être","s'est fait"], answer: 2, explain: "Passive voice with modal: 'doit être installé' = 'must be installed'. After 'être', the past participle 'installé' is required, not the infinitive 'installer'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-11-mr5o5rye", question: "Si tu ___ plus patient, tu aurais trouvé la solution plus rapidement.", options: ["étais","avais été","serais","es"], answer: 1, explain: "This is a past conditional sentence. The 'si' clause in the plus-que-parfait (avais été) refers to a past condition that did not happen, leading to a past hypothetical result.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-12-mr5o5rye", question: "Il n'y a personne ___ puisse résoudre ce problème à part lui.", options: ["qui","que","dont","où"], answer: 0, explain: "When the antecedent is a negative or indefinite pronoun (personne, rien, aucun), the subjunctive mood is often used, and 'qui' introduces the subject of the subjunctive verb.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-13-mr5o5rye", question: "Ils ___ dû annuler leur voyage à cause de la pandémie.", options: ["pouvaient","ont pu","auraient","ont dû"], answer: 3, explain: "The passé composé 'ont dû' expresses a past obligation or necessity. They were obliged to cancel their trip.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-14-mr5o5rye", question: "C'est de cette façon ___ il a réussi à convaincre tout le monde.", options: ["qui","que","où","dont"], answer: 1, explain: "This is a cleft sentence emphasizing an adverbial phrase ('de cette façon'). 'C'est... que' is used when emphasizing anything other than the subject.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-15-mr5o5rye", question: "Bien qu'il ___ très fatigué, il a continué à travailler.", options: ["était","soit","fût","est"], answer: 1, explain: "The conjunction 'bien que' (although) always requires the subjunctive mood. 'Soit' is the subjunctive present of 'être'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-16-mr5o5rye", question: "Si j'étais riche, j'___ ce tour du monde l'année dernière.", options: ["faisais","ferais","aurais fait","ai fait"], answer: 2, explain: "This is a mixed conditional sentence. The 'si' clause in the imparfait (j'étais riche) expresses a present hypothetical condition, and the main clause in the conditionnel passé (aurais fait) expresses a hypothetical past result.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-17-mr5o5rye", question: "Ces livres ___ être rangés avant la fermeture de la bibliothèque.", options: ["doivent","devront","sont","ont"], answer: 0, explain: "The passive construction 'doivent être rangés' indicates a present obligation or necessity for the books to be put away.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-18-mr5o5rye", question: "Nous craignons qu'il ne ___ pas assez de temps pour finir le projet.", options: ["aura","ait","avait","a"], answer: 1, explain: "Verbs expressing fear or doubt, such as 'craindre que', require the subjunctive mood. 'Ait' is the subjunctive present of 'avoir'.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-19-mr5o5rye", question: "Ce qui ___ est l'efficacité de la nouvelle équipe.", options: ["importe","importait","importerait","est importé"], answer: 0, explain: "This is an impersonal cleft sentence using 'Ce qui' as the subject to emphasize a concept or idea. 'Importe' is the present indicative form.", language: "fr", level: "B2" },
  { id: "q-fr-b2-gemini-20-mr5o5rye", question: "Elle ___ être surprise de ma visite impromptue.", options: ["peut","doit","aurait","pourrait"], answer: 1, explain: "The modal verb 'devoir' in the present tense can express a strong probability or assumption. 'Elle doit être surprise' means 'She must be surprised'.", language: "fr", level: "B2" },
  // ── it (40 items) ──
  { id: "q-it-b1-gemini-1-mr5ug5rg", question: "Quando ___ bambino, giocavo spesso nel parco.", options: ["sono stato","ero","fui","stavo"], answer: 1, explain: "The imperfetto (ero) is used to describe a state or a habitual action in the past, like 'when I was a child'. The passato prossimo (sono stato) indicates a completed action at a specific point in time.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-2-mr5ug5rg", question: "Ieri sera ___ un film interessante in televisione.", options: ["vedevamo","abbiamo visto","vedemmo","vedremmo"], answer: 1, explain: "The passato prossimo (abbiamo visto) is used for a completed action that occurred at a specific time in the past ('ieri sera' - yesterday evening).", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-3-mr5ug5rg", question: "Mentre lei ___ la cena, ha squillato il telefono.", options: ["preparava","ha preparato","preparerà","preparerebbe"], answer: 0, explain: "The imperfetto (preparava) is used to describe an ongoing action in the past that was interrupted by another action (the phone ringing), which is expressed with the passato prossimo.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-4-mr5ug5rg", question: "Non ___ più Marco da quando si è trasferito a Roma.", options: ["vedevo","ho visto","vidi","avrei visto"], answer: 1, explain: "The passato prossimo (ho visto) is used for a specific action that started in the past and has a connection to the present ('da quando' indicates a duration up to now). Imperfetto (vedevo) would imply a habitual action.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-5-mr5ug5rg", question: "Se domani ___ bel tempo, andremo al mare.", options: ["fosse","fatto","farà","farebbe"], answer: 2, explain: "In first conditional (se + future), Italian requires future tense in both clauses: 'Se domani farà bel tempo, andremo al mare'. The future 'farà' matches 'andremo'. Note: while 'fa' (present) is sometimes used colloquially, the standard B1 form is 'farà'.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-6-mr5ug5rg", question: "Se ___ più soldi, comprerei una casa più grande.", options: ["avevo","avrei","avessi","ho"], answer: 2, explain: "This is a second conditional sentence (periodo ipotetico della possibilità/irrealtà). It expresses a hypothetical or less probable condition using 'se' + congiuntivo imperfetto, followed by the condizionale semplice.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-7-mr5ug5rg", question: "Se tu studiassi di più, ___ gli esami.", options: ["supereresti","supererai","supereranno","superavi"], answer: 0, explain: "This is a second conditional sentence. The 'se' clause uses the congiuntivo imperfetto ('studiassi'), and the main clause requires the condizionale semplice ('supereresti') to express a hypothetical outcome.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-8-mr5ug5rg", question: "Se non ti sbrighi, ___ in ritardo.", options: ["arriverai","arriveresti","arrivassi","arrivavi"], answer: 0, explain: "This is a first conditional sentence expressing a real or probable consequence. The condition is in the present tense ('non ti sbrighi'), and the result is in the future simple ('arriverai').", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-9-mr5ug5rg", question: "Ha detto che ___ stanco e voleva riposare.", options: ["è","sarebbe","era","fossi"], answer: 2, explain: "In reported speech, if the main verb (ha detto) is in the past, the verb in the reported clause often shifts back in tense. 'Sono stanco' becomes 'era stanco' in the imperfetto.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-10-mr5ug5rg", question: "Mi ha chiesto se ___ al concerto.", options: ["andrei","ero andato","fossi andato","andavo"], answer: 2, explain: "When reporting a question in the past, 'sei andato?' (passato prossimo) often shifts to 'fossi andato' (congiuntivo trapassato) if the main verb is in the past ('mi ha chiesto').", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-11-mr5ug5rg", question: "La professoressa ha spiegato che la lezione ___ il giorno dopo.", options: ["è","sarebbe stata","fosse","sarà"], answer: 1, explain: "In reported speech, a future event relative to a past main verb ('ha spiegato') is expressed with the future in the past, which is the condizionale passato ('sarebbe stata').", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-12-mr5ug5rg", question: "Lui mi ha promesso che ___ la verità.", options: ["diceva","direbbe","avrebbe detto","dice"], answer: 2, explain: "When reporting a future action from a past perspective ('mi ha promesso'), the future simple ('dirà') becomes the condizionale composto ('avrebbe detto') in reported speech.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-13-mr5ug5rg", question: "Ho incontrato l'amico ___ mi hai parlato.", options: ["che","cui","quale","di cui"], answer: 3, explain: "The relative pronoun 'di cui' is used when the verb in the relative clause requires the preposition 'di' (parlare di qualcosa/qualcuno). It means 'about whom' or 'of whom'.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-14-mr5ug5rg", question: "Questo è il libro ___ ho letto ieri.", options: ["di cui","che","il quale","a cui"], answer: 1, explain: "The relative pronoun 'che' is used as a direct object ('ho letto il libro'). It can refer to both people and things, and does not require a preposition before it.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-15-mr5ug5rg", question: "La città ___ viviamo è molto antica.", options: ["che","cui","dove","a cui"], answer: 2, explain: "The relative adverb 'dove' (where) is used to introduce a relative clause that refers to a place. Alternatives like 'in cui' or 'nella quale' could also be used, but 'dove' is simpler.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-16-mr5ug5rg", question: "La ragazza ___ è arrivata è mia sorella.", options: ["quale","che","a cui","di cui"], answer: 1, explain: "The relative pronoun 'che' is used here as the subject of the relative clause ('la ragazza è arrivata'). It means 'who' or 'that'.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-17-mr5ug5rg", question: "La torta ___ da mia nonna.", options: ["ha preparato","è stata preparata","prepara","preparava"], answer: 1, explain: "This sentence requires the passive voice, indicating that the cake received the action. The passato prossimo passive is formed with 'essere' in the passato prossimo + past participle ('è stata preparata').", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-18-mr5ug5rg", question: "Molti alberi ___ dal vento forte.", options: ["abbatterono","sono stati abbattuti","stanno abbattendo","avrebbero abbattuto"], answer: 1, explain: "The passive voice is formed with a form of 'essere' or 'venire' followed by the past participle. 'Sono stati abbattuti' correctly expresses the action of being cut down in the past.", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-19-mr5ug5rg", question: "Le nuove regole ___ dal governo il prossimo anno.", options: ["introducono","saranno introdotte","sono state introdotte","introdurrebbero"], answer: 1, explain: "This sentence requires the future passive voice because the action will happen in the future ('il prossimo anno'). It is formed with 'essere' in the future simple + past participle ('saranno introdotte').", language: "it", level: "B1" },
  { id: "q-it-b1-gemini-20-mr5ug5rg", question: "Il museo ___ ogni giorno da molti turisti.", options: ["visita","visiterà","viene visitato","avesse visitato"], answer: 2, explain: "The passive voice using 'venire' + past participle is often used to describe habitual or ongoing actions, emphasizing the process. 'Viene visitato' means 'is visited' regularly.", language: "it", level: "B1" },
  { id: "q-it-b2-gemini-1-mr5ugzvf", question: "Se ___ studiato di più, ora non avresti questi problemi.", options: ["avevi","avessi","avrai","hai"], answer: 1, explain: "This is a mixed conditional expressing an unreal condition in the past ('If you had studied more') leading to a consequence in the present ('you wouldn't have these problems now'). It requires the trapassato congiuntivo in the 'se' clause.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-2-mr5ugzvf", question: "Benché ___ stanco, ha continuato a lavorare fino a tardi.", options: ["era","sia","è","fosse"], answer: 3, explain: "The conjunction 'benché' (although) requires the subjunctive mood. Since the main clause describes a past action ('ha continuato'), the imperfect subjunctive 'fosse' is appropriate for a state simultaneous with or prior to that action.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-3-mr5ugzvf", question: "La decisione ___ presa dal consiglio la settimana scorsa.", options: ["era stata","venne","sarà","sarebbe"], answer: 1, explain: "'venne presa' is the passive form of 'venire' in passato remoto, used in formal/written Italian for completed past events. 'sarà' (future) and 'sarebbe' (conditional) don't match 'la settimana scorsa'; 'è stata' (passato prossimo) is acceptable in spoken Italian but 'venne' is the formal standard.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-4-mr5ugzvf", question: "___ a Marco che ho dato il libro, non a te.", options: ["Era","È","Fu","Stato"], answer: 1, explain: "Cleft sentences use 'È... che' to emphasize a specific part of the sentence, in this case, the indirect object 'a Marco'. 'È' is used because the emphasis itself is a present statement.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-5-mr5ugzvf", question: "Non ha risposto al telefono, ___ essere uscito.", options: ["doveva","potresti","deve","dovrebbe"], answer: 2, explain: "'Deve essere uscito' expresses a strong probability or logical deduction about a past event. 'Dovere' in the present followed by the infinitive perfect 'essere uscito' is used for this purpose.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-6-mr5ugzvf", question: "Cerchiamo qualcuno che ___ parlare fluentemente il tedesco.", options: ["sa","saprà","sappia","saprebbe"], answer: 2, explain: "When the antecedent of a relative clause is indefinite or uncertain ('qualcuno che'), the subjunctive mood is often used to express uncertainty or a desired quality. 'Sappia' is the present subjunctive of 'sapere'.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-7-mr5ugzvf", question: "Se non ___ così timido, avrebbe fatto la proposta anni fa.", options: ["è","fosse","era","sia"], answer: 1, explain: "This mixed conditional expresses a present unreal condition ('If he weren't so shy') leading to a past hypothetical consequence ('he would have proposed years ago'). It requires the imperfect subjunctive in the 'se' clause.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-8-mr5ugzvf", question: "Questo problema ___ risolto al più presto.", options: ["verrà","stava","è","va"], answer: 3, explain: "'va risolto' uses 'andare' + past participle to express necessity, meaning 'must be solved'. This is a formal idiomatic construction. 'stava' (imperfetto) doesn't express necessity; 'deve essere' is grammatically correct but the exercise focuses on the 'andare + pp' form.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-9-mr5ugzvf", question: "È importante che tu ___ attento durante la lezione.", options: ["sei","eri","sia","fossi"], answer: 2, explain: "Impersonal expressions like 'È importante che' always require the subjunctive mood in the subordinate clause. 'Sia' is the present subjunctive of 'essere'.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-10-mr5ugzvf", question: "___ ieri sera che ci siamo incontrati per la prima volta.", options: ["Fu","Era","È","Stato"], answer: 2, explain: "Cleft sentences use 'È... che' to emphasize a specific element. Here, 'È ieri sera che...' emphasizes the time of the event. 'È' is used because the emphasis itself is a present statement.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-11-mr5ugzvf", question: "Con più tempo, ___ finito il lavoro entro venerdì.", options: ["potrei","potevo","avrei saputo","avrei potuto"], answer: 3, explain: "'Avrei potuto' (conditional perfect of 'potere') expresses a hypothetical ability or possibility in the past, given a different condition ('Con più tempo').", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-12-mr5ugzvf", question: "Dubito che ___ in tempo per la riunione.", options: ["arriva","arriverà","arrivi","arrivava"], answer: 2, explain: "Verbs expressing doubt, uncertainty, or denial (like 'dubitare') require the subjunctive mood in the subordinate clause. 'Arrivi' is the present subjunctive.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-13-mr5ugzvf", question: "Se ___ saputo la verità, non ti darei questo consiglio.", options: ["ho","avessi","avevo","avrei"], answer: 1, explain: "This is a mixed conditional where an unreal past condition ('If I had known the truth') leads to a present unreal consequence ('I wouldn't give you this advice'). The 'se' clause requires the trapassato congiuntivo.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-14-mr5ugzvf", question: "In Italia, ___ mangia molto bene.", options: ["lo","ci","si","è"], answer: 2, explain: "The 'si passivante' (or impersonal 'si') is used to express general actions without specifying the agent, often translating to 'one eats' or 'people eat'. It requires the verb to be in the third person singular.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-15-mr5ugzvf", question: "Ti spiego di nuovo, affinché tu ___ capire meglio.", options: ["puoi","potrai","potresti","possa"], answer: 3, explain: "The conjunction 'affinché' (in order that, so that) always introduces a final clause and requires the subjunctive mood. 'Possa' is the present subjunctive of 'potere'.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-16-mr5ugzvf", question: "La porta era aperta, ___ dimenticata da qualcuno.", options: ["deve essere stata","doveva essere","è stata","dovrebbe essere stata"], answer: 0, explain: "'Deve essere stata dimenticata' expresses a strong deduction or assumption about a past event, using 'dovere' in the present followed by the infinitive perfect passive.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-17-mr5ugzvf", question: "___ il professore che ci ha dato questo difficile compito.", options: ["Fu","Era","Stato","È"], answer: 3, explain: "This is a cleft sentence ('È... che') emphasizing the subject 'il professore'. Even though the action (dare) is past, the emphasis is a present statement.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-18-mr5ugzvf", question: "Malgrado ___ piovuto tutto il giorno, siamo andati a fare una passeggiata.", options: ["aveva","avendo","ha","abbia"], answer: 3, explain: "'Malgrado' requires congiuntivo. 'abbia piovuto' (passato congiuntivo) is correct for recent past completed action. 'avendo' (gerund) and 'avere' (infinitive) don't follow 'malgrado'; 'avesse' (trapassato) would require another past reference point.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-19-mr5ugzvf", question: "Se ___ più tempo libero, sarei andato al concerto.", options: ["ho","avevo","avrei","avessi"], answer: 3, explain: "This mixed conditional expresses a present unreal condition ('If I had more free time now') leading to a past unreal consequence ('I would have gone to the concert'). The 'se' clause requires the imperfect subjunctive.", language: "it", level: "B2" },
  { id: "q-it-b2-gemini-20-mr5ugzvf", question: "Qui ___ vive bene, non c'è molto stress.", options: ["lo","ci","ne","si"], answer: 3, explain: "The 'si impersonale' is used with intransitive verbs (like 'vivere') to express a general action without a specific subject, translating to 'one lives' or 'people live'.", language: "it", level: "B2" },
  // ── ja (80 items) ──
  { id: "q-ja-n2-gemini-1-mqzvvf2z", question: "彼は体調が悪い___、仕事に出かけた。", options: ["のに","にもかかわらず","ても","けど"], answer: 1, explain: "「〜にもかかわらず」means \"despite\" or \"even though\" and expresses that something happened contrary to expectations, often in a more formal context than 「のに」.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-2-mqzvvf2z", question: "多くの困難があった___、その計画は成功に終わった。", options: ["のだが","だから","にもかかわらず","なので"], answer: 2, explain: "「〜にもかかわらず」is used to indicate that something happened or proceeded despite a hindering factor, implying a surprising or unexpected outcome.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-3-mqzvvf2z", question: "天候不順___、収穫量は例年並みだった。", options: ["けれども","なのに","だがしかし","にもかかわらず"], answer: 3, explain: "「〜にもかかわらず」connects a cause or condition with a result that is contrary to what would normally be expected. It can connect nouns/na-adjectives directly or with 「であるにもかかわらず」.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-4-mqzvvf2z", question: "遅い時間であった___、彼は快く相談に応じてくれた。", options: ["として","だけあって","にもかかわらず","からといって"], answer: 2, explain: "「〜にもかかわらず」is used when an action or state occurs contrary to what one would expect from the preceding condition. In this case, despite it being late, he kindly responded.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-5-mqzvvf2z", question: "お忙しい___、大変恐縮ですが、少々お時間をいただけますでしょうか。", options: ["時に","ところを","際に","中で"], answer: 1, explain: "「〜ところを」is used to express an apology or gratitude when intruding upon someone's state or situation, often in formal contexts. Here, it means \"while you are busy.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-6-mqzvvf2z", question: "夜遅くお休みの___、お電話してしまい、申し訳ございません。", options: ["間に","せいで","ときに","ところを"], answer: 3, explain: "「〜ところを」is a formal expression used when you apologize for disturbing someone during a specific state or action, such as being asleep.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-7-mqzvvf2z", question: "先生がご指導されている___、誠に恐縮ですが、少しお伺いしたいことがあります。", options: ["最中に","ために","ときには","ところを"], answer: 3, explain: "「〜ところを」is used when you interrupt or intrude upon someone's ongoing action or state, often accompanied by an apology or request.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-8-mqzvvf2z", question: "大変お困りの___、微力ながらお手伝いさせていただけませんか。", options: ["状況を","状態に","ところを","事態を"], answer: 2, explain: "「〜ところを」is used to express sympathy or an offer of help when someone is in a difficult situation. It indicates intervening at that specific moment.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-9-mqzvvf2z", question: "彼は宿題をやり___、遊びに行ってしまった。", options: ["きりで","とおりに","っぱなしで","ままで"], answer: 2, explain: "「〜っぱなし」means \"leaving something in a state\" or \"keeping on doing something,\" often implying negligence or a continuous, uncontrolled action. Here, it means \"leaving the homework unfinished.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-10-mqzvvf2z", question: "エアコンをつけ___寝てしまい、風邪をひいてしまった。", options: ["たままで","ておくまま","っぱなしで","終わったまま"], answer: 2, explain: "「〜っぱなし」indicates that an action was left in its current state, often with a negative nuance of carelessness or neglect. Here, the air conditioner was left on.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-11-mqzvvf2z", question: "水を出し___にしないでください。もったいないですよ。", options: ["だけ","きり","っぱなし","ままで"], answer: 2, explain: "「〜っぱなし」is used to describe leaving something in an undesirable or careless state, such as leaving the water running.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-12-mqzvvf2z", question: "長時間立ち___の仕事で、足が棒のようになってしまった。", options: ["きり","っぱなし","つづけ","たまま"], answer: 1, explain: "「〜っぱなし」can also indicate that an action continued without interruption for a long time, often leading to a negative consequence like fatigue.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-13-mqzvvf2z", question: "彼女の言葉には、どこか皮肉___響きがあった。", options: ["らしい","ふうな","めいた","のような"], answer: 2, explain: "「〜めく」attaches to nouns to indicate \"to show signs of,\" \"to have the appearance of,\" or \"to be tinged with.\" 「皮肉めいた」means \"tinged with sarcasm.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-14-mqzvvf2z", question: "街にはもう春___雰囲気が漂い始めている。", options: ["らしい","っぽい","のような","めいた"], answer: 3, explain: "「〜めく」is used to describe something taking on the characteristics or atmosphere of the noun it's attached to. Here, the town is beginning to feel like spring.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-15-mqzvvf2z", question: "彼の笑顔はいつも謎___で、本心が読めない。", options: ["のようで","らしいので","っぽいので","めいていて"], answer: 3, explain: "「〜めく」is used to describe something having the quality or characteristic of the noun. 「謎めいて」means \"mysterious-looking\" or \"having a mysterious air.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-16-mqzvvf2z", question: "その話はあまりにも嘘___、誰も信じなかった。", options: ["のようで","めいていて","っぽいので","らしいので"], answer: 1, explain: "「〜めく」can be used to describe something that strongly appears to be a certain way, even if it's not explicitly stated. 「嘘めいた」means \"seeming like a lie.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-17-mqzvvf2z", question: "京都へ旅行する___、金閣寺はぜひ訪れるべきだ。", options: ["と","ば","なら","たら"], answer: 2, explain: "「〜なら」is often used to state a condition or topic, and then offer advice or a suggestion related to that condition. It functions like \"if it's about X, then Y.\"", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-18-mqzvvf2z", question: "この本に興味がある___、図書館で借りられますよ。", options: ["れば","だったら","のなら","と"], answer: 2, explain: "「〜なら」is used to provide information or a suggestion based on the listener's stated or implied interest or situation. 「〜のなら」emphasizes the premise.", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-19-mqzvvf2z", question: "もし分からないことが___、遠慮なく質問してください。", options: ["あれば","あったら","あると","あるのなら"], answer: 0, explain: "「〜ば」是条件形。「分からないことがあれば」意为「如果有不懂的事」，与后句「遠慮なく質問してください」（请随意提问）构成条件-请求句型。", language: "ja", level: "N2" },
  { id: "q-ja-n2-gemini-20-mqzvvf2z", question: "田中さんのスケジュール___、秘書に確認するのが一番です。", options: ["ならば","となると","とすれば","でしたら"], answer: 1, explain: "「〜となると」意为「说到……」「一旦提到……」，用于引出话题。「田中さんのスケジュールとなると」表示「提到田中先生的日程」，与后句「最好问秘书」构成自然衔接。", language: "ja", level: "N2" },
  { id: "q-ja-n3-gemini-1-mr5nu56w", question: "毎日、日本語を話す___しています。", options: ["こと","ため","ように","もの"], answer: 2, explain: "「〜ようにする」 expresses making an effort or trying to do something as a habit or goal. Here, it means 'I try to speak Japanese every day.'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-2-mr5nu56w", question: "健康のために、夜は早く___ようにしています。", options: ["寝られる","寝させる","寝ない","寝る"], answer: 3, explain: "「〜ようにする」 indicates making a conscious effort to establish a habit. Here, it means 'I try to sleep early for my health.'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-3-mr5nu56w", question: "お客様に失礼のない___、気をつけるようにしてください。", options: ["こと","ため","よう","もの"], answer: 2, explain: "「〜ようにする」 is used to describe making an effort to achieve a certain state or outcome. In this case, it means to be careful not to be rude to customers.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-4-mr5nu56w", question: "来月、大阪へ___になりました。", options: ["転勤させる","転勤される","転勤すること","転勤する"], answer: 2, explain: "「〜ことになる」 indicates that something has been decided by others or it has been arranged for you, often beyond one's personal will. It implies a decision or a consequence.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-5-mr5nu56w", question: "急な出張で、明日の会議には___ことになりました。", options: ["参加する","参加しない","参加できない","参加しないよう"], answer: 2, explain: "「〜ことになる」 is used to express that something has been decided or it turns out that way, often implying it's beyond one's personal will, such as being unable to attend.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-6-mr5nu56w", question: "この書類は来週までに提出___ことになっています。", options: ["する","すること","される","されるよう"], answer: 1, explain: "「〜ことになっている」 means 'it has been decided that...' or 'it is supposed to be done.' It indicates a rule, custom, or arrangement.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-7-mr5nu56w", question: "宿題を___てしまいました。", options: ["忘れる","忘れ","忘れて","忘れてい"], answer: 1, explain: "「〜てしまう」表示遗憾或完成。「忘れ」是动词「忘れる」的連用形，接「てしまう」构成「忘れてしまった」（不小心忘了）。", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-8-mr5nu56w", question: "大切な書類をうっかり ___ 、本当に困った。", options: ["捨てた","捨てて","捨てる","捨てよう"], answer: 1, explain: "「〜て、〜」表示原因或先后顺序。「捨てて」是动词「捨てる」的 te 形，表示因不小心丢掉而导致困扰。", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-9-mr5nu56w", question: "彼はケーキを全部___しまった。", options: ["食べる","食べ","食べて","食べられ"], answer: 2, explain: "「〜てしまう」 expresses the completion of an action, often with a nuance of regret or something being done entirely.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-10-mr5nu56w", question: "電車に乗り遅れて___、遅刻してしまった。", options: ["しまわない","しまったら","しまえば","しまって"], answer: 3, explain: "「〜てしまう」 describes an action that has been completed, often with a feeling of regret or an unintended outcome. Here, it means 'I missed the train and ended up being late.'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-11-mr5nu56w", question: "窓が___います。", options: ["開けて","開いて","開かれ","開かせ"], answer: 1, explain: "「開く」 (intransitive) means 'to open' (itself), while 「開ける」 (transitive) means 'to open' (something). The window is in an open state.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-12-mr5nu56w", question: "誰かがドアを___。", options: ["閉まった","閉めた","閉まりました","閉められ"], answer: 1, explain: "「閉める」 (transitive) means 'to close' something, requiring an agent. 「閉まる」 (intransitive) means 'to close' (itself).", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-13-mr5nu56w", question: "先生がホワイトボードに漢字を___。", options: ["書かれた","書いた","書かれる","書いられた"], answer: 1, explain: "「書く」 is a transitive verb meaning 'to write.' The teacher is performing the action of writing on the whiteboard.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-14-mr5nu56w", question: "電気が___いるので、つけましょうか。", options: ["消している","消された","消させられた","消えている"], answer: 3, explain: "「消える」 (intransitive) means 'to go out' or 'to be off.' 「消す」 (transitive) means 'to turn off' or 'to extinguish.' The light is in an 'off' state.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-15-mr5nu56w", question: "日本語は___、___難しくなります。", options: ["勉強するとするほど","勉強したらするほど","勉強すればするほど","勉強するならするほど"], answer: 2, explain: "「〜ば〜ほど」 is used to express that as one thing changes, another thing changes proportionally. It means 'the more you study, the more difficult it becomes.'", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-16-mr5nu56w", question: "高い山に___、気温は___なります。", options: ["登れば登るほど、低く","登ったら登るほど、低く","登れば登って、低く","登ると登るほど、低く"], answer: 0, explain: "「〜ば〜ほど」表示「越……越……」。「登れば登るほど」意为「越往上爬越……」，与「低くなる」（变低）搭配，表示海拔越高气温越低。", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-17-mr5nu56x", question: "彼は初めて日本に来た___、日本語がとても上手だ。", options: ["なのに","にもかかわらず","だから","にしては"], answer: 1, explain: "「にもかかわらず」是书面语的让步表达，意为「尽管……」。「なのに」虽也表示让步，但语体偏口语，与正式书面语语境不符。", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-18-mr5nu56x", question: "このアパートは駅に近い___、家賃が安い。", options: ["だけあって","だけに","ことから","にしては"], answer: 3, explain: "「にしては」表示「作为……来说」。「だけあって」意为「不愧是」，语义虽相近但用法不同；这里考查「にしては」的让步评价用法。", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-19-mr5nu56x", question: "お客様、___お待ちください。", options: ["お","ご","の","に"], answer: 0, explain: "「お」 is added to Japanese origin nouns or verb stems to show politeness or respect. 「お待ちください」 is a polite request to wait.", language: "ja", level: "N3" },
  { id: "q-ja-n3-gemini-20-mr5nu56x", question: "先生、___質問があります。", options: ["お","に","を","ご"], answer: 3, explain: "「ご」 is added to Chinese origin nouns or verb stems to show politeness or respect. 「ご質問」 is the polite form of 'questions.'", language: "ja", level: "N3" },
  { id: "q-ja-n4-gemini-1-mr5ntfsu", question: "昨日、友達と映画を___。", options: ["見る","見ます","見た","見ています"], answer: 2, explain: "The た-form is used to express past actions or completed actions. \"昨日\" (yesterday) indicates a past event.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-2-mr5ntfsu", question: "私は毎日、日本語のニュースを___のが好きです。", options: ["読みます","読んで","読む","読んだ"], answer: 2, explain: "The dictionary form (辞書形) is used before nouns or nominalizers like \"の\" when describing an action or state, such as in \"〜のが好きです\".", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-3-mr5ntfsu", question: "ここでタバコを ___ でください。", options: ["吸う","吸わない","吸った","吸おう"], answer: 1, explain: "「〜ないでください」是表示禁止的礼貌说法，意为「请不要……」。「吸わないでください」意为「请不要吸烟」。", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-4-mr5ntfsu", question: "彼女は赤いセーターを___います。", options: ["着る","着た","着て","着よう"], answer: 2, explain: "\"〜ています\" describes a continuous action or a resulting state. \"着ています\" means \"is wearing,\" indicating a state.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-5-mr5ntfsu", question: "今、母は料理を___います。", options: ["作る","作った","作って","作ろう"], answer: 2, explain: "\"〜ています\" indicates an action that is currently in progress. Here, \"作っています\" means \"is making\" or \"is cooking.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-6-mr5ntfsu", question: "私は漢字をたくさん___ことができます。", options: ["書く","書いた","書いて","書き"], answer: 0, explain: "The construction \"辞書形 + ことができます\" expresses the ability to do something. \"書く\" is the dictionary form of \"to write.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-7-mr5ntfsu", question: "もし雨が___、ピクニックは中止です。", options: ["降る","降れば","降ったら","降っても"], answer: 2, explain: "The \"〜たら\" conditional form expresses a condition and its consequence, often implying a specific, completed action in the past or future. \"降ったら\" means \"if it rains.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-8-mr5ntfsu", question: "時間が___、図書館に行きます。", options: ["ある","あれば","あったら","あって"], answer: 1, explain: "The \"〜ば\" conditional form is often used for general conditions or to state a condition for a desirable outcome. \"あれば\" means \"if there is.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-9-mr5ntfsu", question: "このボタンを___、ドアが開きます。", options: ["押す","押せば","押したら","押すと"], answer: 3, explain: "The \"〜と\" conditional form is used for natural consequences, inevitable results, or established facts. When you press the button, the door opens automatically.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-10-mr5ntfsu", question: "私は学生___。", options: ["だ","である","です","でする"], answer: 2, explain: "\"です\" is the polite form of \"だ\" (to be) and is used at the end of sentences to show politeness in Japanese.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-11-mr5ntfsu", question: "富士山に一度___ことがあります。", options: ["登る","登った","登って","登り"], answer: 1, explain: "The structure \"た-form + ことがあります\" expresses having the experience of doing something in the past. \"登ったことがあります\" means \"I have climbed before.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-12-mr5ntfsu", question: "毎日日本語を___ために、一生懸命勉強しています。", options: ["話します","話した","話す","話して"], answer: 2, explain: "\"辞書形 + ために\" indicates the purpose or reason for an action. \"話すために\" means \"in order to speak.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-13-mr5ntfsu", question: "毎日運動___と、健康になりませんよ。", options: ["する","しない","して","した"], answer: 1, explain: "\"ない-form + と\" is a conditional expression meaning \"if you don't do (something).\" Here, \"しないと\" means \"if you don't do (exercise).\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-14-mr5ntfsu", question: "私は毎朝ジョギング___います。", options: ["する","した","して","しよう"], answer: 2, explain: "\"〜ています\" can also describe a habitual or repeated action. \"ジョギングしています\" means \"I jog every morning.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-15-mr5ntfsu", question: "彼は日本語の新聞を___ことができます。", options: ["読む","読んだ","読んで","読め"], answer: 0, explain: "\"辞書形 + ことができます\" indicates the ability or potential to do something. \"読む\" is the dictionary form of \"to read.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-16-mr5ntfsu", question: "疲れた___、少し休んでください。", options: ["たら","れば","と","なら"], answer: 0, explain: "When the condition is already in the た-form, \"〜たら\" is used to express a condition, often for a suggestion or request. \"疲れたら\" means \"if you get tired.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-17-mr5ntfsu", question: "もっと勉強___、試験に合格できます。", options: ["する","すれば","したら","すると"], answer: 1, explain: "The \"〜ば\" conditional form is used for general conditions, often implying a logical outcome or advice. \"勉強すれば\" means \"if you study.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-18-mr5ntfsu", question: "春に___、桜が咲きます。", options: ["なる","なれば","なったら","なると"], answer: 3, explain: "\"〜と\" is used for universal truths or natural, inevitable consequences. When spring comes, cherry blossoms bloom.", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-19-mr5ntfsu", question: "私はまだ宿題を___いません。", options: ["する","しません","していません","して"], answer: 2, explain: "\"〜ていません\" is the polite negative form of \"〜ています,\" indicating an action has not yet been completed. It means \"I have not done (my homework) yet.\"", language: "ja", level: "N4" },
  { id: "q-ja-n4-gemini-20-mr5ntfsu", question: "レポートはもう全部___。", options: ["書きます","書いた","書いています","書く"], answer: 1, explain: "The た-form indicates a completed action. \"もう全部書いた\" means \"I have already written all of it.\"", language: "ja", level: "N4" },
  { id: "q-ja-n5-gemini-1-mr5nstxm", question: "わたし ___ 学生です。", options: ["は","が","を","に"], answer: 0, explain: "「は」は文の主題を示す助詞です。ここでは「わたし」が主題であることを示します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-2-mr5nstxm", question: "毎日、日本語 ___ 勉強します。", options: ["は","が","を","で"], answer: 2, explain: "動詞「勉強します」の目的語「日本語」を示します。目的語には「を」を使います。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-3-mr5nstxm", question: "きのう、デパート ___ 行きました。", options: ["に","で","を","が"], answer: 0, explain: "「に」是目的地助词，表示移动的目的地。「で」是动作场所，「を」是宾语，「が」是主语，均不用于目的地。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-4-mr5nstxm", question: "わたしは駅のそばのカフェ ___ コーヒーを飲みます。", options: ["が","を","に","で"], answer: 3, explain: "「で」は、動作が行われる場所を示します。「カフェで飲みます」でカフェがコーヒーを飲む場所であることを示します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-5-mr5nstxm", question: "毎朝、ごはんを (食べる)。", options: ["食べます","食べた","食べるます","食べて"], answer: 0, explain: "動詞「食べる」の丁寧な現在形/未来形は「食べます」です。これは習慣的な行動を表します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-6-mr5nstxm", question: "このかばんは (きれい) です。", options: ["きれいな","きれいなです","きれいです","きれいでした"], answer: 2, explain: "な形容詞の肯定形は、形容詞の語幹に「です」を付けます。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-7-mr5nstxm", question: "テレビを (見る) 音楽を聞きます。", options: ["見て","見る","見ました","見るて"], answer: 0, explain: "複数の動作を順に接続する場合、最初の動詞をて形にします。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-8-mr5nstxm", question: "ここに (座る) ください。", options: ["座ります","座って","座らない","座った"], answer: 1, explain: "依頼や指示をする際に動詞のて形に「ください」を続けます。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-9-mr5nstxm", question: "わたしはコーヒーが嫌いです。わたしはコーヒーを ___。", options: ["飲みます","飲まない","飲んだ","飲もう"], answer: 1, explain: "「嫌いです」表示讨厌，是消极情感。前句说讨厌咖啡，后句自然是否定「不喝」，故用「飲まない」。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-10-mr5nstxm", question: "わたしは友達 ___ 映画を見ます。", options: ["を","で","に","と"], answer: 3, explain: "「と」は、誰かと一緒に行動する際に使われます。「友達と」で友達と一緒に映画を見ることを表します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-11-mr5nstxm", question: "わたしは日本語が (分かる) 。", options: ["分かります","分からない","分かって","分かった"], answer: 0, explain: "能力や理解を表す際によく使われる「わかります」の丁寧形です。「～がわかります」の形で使われます。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-12-mr5nstxm", question: "学校 ___ 行きます。", options: ["へ","で","を","が"], answer: 0, explain: "「へ」是目的地助词，表示移动方向。「学校へ行きます」表示往学校方向移动。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-13-mr5nstxm", question: "授業は9時 ___ 始まります。", options: ["まで","に","から","で"], answer: 2, explain: "「から」は動作の開始点や起点を示します。ここでは「9時から」で9時が授業の開始時間であることを表します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-14-mr5nstxm", question: "授業は5時 ___ 終わります。", options: ["から","で","に","まで"], answer: 2, explain: "「に」是时间点助词，用于表示动作发生的具体时间。「終わる」是瞬间动词，与具体时间点「5時に」搭配。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-15-mr5nstxm", question: "これ ___ わたしの本です。", options: ["は","を","が","の"], answer: 0, explain: "「は」是主题助词，提示句子的主题。「これはわたしの本です」中「これ」是主题，用「は」标记。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-16-mr5nstxm", question: "ここで写真を (撮る) もいいですか。", options: ["撮って","撮るて","撮りて","撮り"], answer: 0, explain: "許可を求めるときは、動詞のて形に「もいいですか」を続けます。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-17-mr5nstxm", question: "ここで (走る) ください。", options: ["走らないで","走ります","走って","走った"], answer: 0, explain: "否定の依頼や禁止を表すには、動詞の「ない形」に「でください」をつけます。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-18-mr5nstxm", question: "毎日、午後7時 ___ テレビを見ます。", options: ["から","に","で","まで"], answer: 1, explain: "特定の日時や時間に動作が行われる場合、「に」を使います。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-19-mr5nstxm", question: "バス ___ 学校に行きます。", options: ["を","は","で","と"], answer: 2, explain: "「で」は、手段や方法を表す助詞です。ここでは「バスで」でバスが学校に行く手段であることを表します。", language: "ja", level: "N5" },
  { id: "q-ja-n5-gemini-20-mr5nstxm", question: "このりんごは (おいしい) ありません。", options: ["おいしく","おいしいく","おいしいで","おいしかった"], answer: 0, explain: "い形容詞の否定形は、語尾の「い」を「く」に変えて「ありません」をつけます。", language: "ja", level: "N5" },
  // ── ko (59 items) ──
  { id: "q-ko-고급-gemini-1-mr5ucjvd", question: "이 연구는 장기간에 걸쳐 ___, 그 결과는 신뢰할 만하다고 할 수 있습니다.", options: ["진행되었으므로","진행되었는데","진행되었지만","진행되더라도"], answer: 0, explain: "-(으)므로 is a formal connective ending meaning \"because\" or \"therefore,\" indicating a cause or reason followed by a result or conclusion. It is commonly used in written language.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-2-mr5ucjvd", question: "한국어는 ___ 흥미로운 언어이다.", options: ["배우면 배울수록","배우고 나면","배울 리가 없다","배운 데다가"], answer: 0, explain: "-(으)ㄹ수록 means \"the more... the more...\" It expresses that as one action or state increases, another action or state also increases proportionally.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-3-mr5ucjvd", question: "아무리 ___ 식사는 꼭 챙겨 먹어야 한다.", options: ["바빠도","바쁘니까","바쁘려면","바빠서"], answer: 0, explain: "-아/어도 means \"even if\" or \"even though.\" It indicates that the action or state in the following clause occurs regardless of the preceding condition.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-4-mr5ucjvd", question: "그는 작가로서 소설을 ___, 동시에 교수로 학생들을 가르치고 있다.", options: ["집필하며","집필했는데","집필하다가","집필하고도"], answer: 0, explain: "-(으)며 is a formal connective ending meaning \"and\" or \"while,\" used to connect two or more actions or states that occur simultaneously or consecutively. It is often used in written contexts.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-5-mr5ucjvd", question: "창문이 강한 바람에 의해 _____.", options: ["깨졌다","깨어졌다","깨뜨렸다","깨지게 했다"], answer: 0, explain: "'깨지다' is the correct passive form of '깨다' (to break something) and means 'to be broken.' '깨어지다' is an incorrect double passive construction.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-6-mr5ucjvd", question: "본 보고서는 심층적인 시장 조사를 바탕으로 작성되었으므로, 기업의 향후 전략 수립에 중요한 자료가 될 _____.", options: ["것입니다","것이다","것이어요","것이라고 한다"], answer: 0, explain: "For a formal written report, the '합쇼체' ending -ㅂ니다/-습니다 is appropriate. '것입니다' is the formal polite ending for making a statement, suitable for reports and official documents.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-7-mr5ucjvd", question: "모든 증거가 그의 무죄를 가리키고 _____, 재판부는 그에게 무죄를 선고했다.", options: ["있으므로","있으면","있지만","있으려고"], answer: 0, explain: "-(으)므로 indicates a formal reason or cause. In this sentence, the evidence pointing to innocence is the reason for the court's verdict.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-8-mr5ucjvd", question: "이 문제는 생각하면 _____ 어려워지는 것 같다.", options: ["생각할수록","생각하더라도","생각하는 대로","생각했던 바와 같이"], answer: 0, explain: "-(으)ㄹ수록 expresses a correlation where an increase in one state or action leads to an increase in another. Here, the more one thinks, the more difficult the problem seems.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-9-mr5ucjvd", question: "아무리 ___ 성공하지 못할 때도 있다.", options: ["노력해도","노력하니까","노력하면서","노력하면"], answer: 0, explain: "-아/어도 signifies \"even if\" or \"even though,\" indicating that the subsequent clause holds true despite the condition presented in the first clause.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-10-mr5ucjvd", question: "이 강연에서는 인공지능의 현재와 미래를 논의 _____, 윤리적 측면까지 다룰 예정이다.", options: ["논의하며","논의할 뿐만 아니라","논의했으나","논의한다면"], answer: 0, explain: "-(으)며 connects multiple actions or topics simultaneously or consecutively, presenting them as a list or concurrent events in a formal context.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-11-mr5ucjvd", question: "아이가 엄마에게 새 신발을 _____.", options: ["신겨 달라고 졸랐다","신기게 되었다","신었으면 했다","신어 주었다"], answer: 0, explain: "'신기다' is the causative form of '신다' (to wear shoes), meaning \"to make someone wear shoes\" or \"to put shoes on someone.\" The child is asking the mother to put shoes on them.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-12-mr5ucjvd", question: "이 제품은 사용자의 편의성을 최우선으로 고려하여 개발되었으므로, 누구나 쉽게 사용할 수 _____.", options: ["있습니다","있어","있을 것이다","있어요"], answer: 0, explain: "'있습니다' is the formal polite ending in '합쇼체', appropriate for formal statements in written documents or presentations.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-13-mr5ucjvd", question: "시험 범위가 광범위 _____, 충분한 준비 시간이 필요하다.", options: ["하므로","해도","하든지","하면서"], answer: 0, explain: "-(으)므로 indicates the reason or cause for the necessity of sufficient preparation time, functioning as \"because\" in a formal written context.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-14-mr5ucjvd", question: "고난을 겪으면 _____ 사람은 더욱 강해진다.", options: ["겪을수록","겪어도","겪는다고 해서","겪기에"], answer: 0, explain: "This grammar point indicates that as the degree of the first action (experiencing hardship) increases, the degree of the second state (becoming stronger) also increases.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-15-mr5ucjvd", question: "밤을 새워 공부 _____, 시험에 통과하지 못할 수도 있다.", options: ["해도","하니까","하면","하느라"], answer: 0, explain: "-아/어도 means \"even if\" or \"even though.\" It suggests that despite the effort of studying all night, failure is still a possibility.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-16-mr5ucjvd", question: "그는 여러 분야의 책을 탐독 _____, 지식을 넓혀 나갔다.", options: ["탐독하며","탐독하다가","탐독했지만","탐독한다면"], answer: 0, explain: "-(으)며 connects two simultaneous or sequential actions in a formal way: reading many books and expanding knowledge.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-17-mr5ucjvd", question: "아이는 엄마에게 손을 잡고 길을 _____.", options: ["건너달라고 했다","건너졌다","건너게 되었다","건너겠다고 했다"], answer: 0, explain: "건너다（过马路）+ -아/어 달라고 하다 表示请求他人帮忙做某事。「길을 건너달라고 했다」意为「请（妈妈）帮忙过马路」。注意「건네다」是独立动词（递交），不是「건너다」的使动形。", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-18-mr5ucjvd", question: "저희는 고객님의 소중한 의견을 적극 반영하여 더 나은 서비스를 제공하도록 노력하 _____.", options: ["겠습니다","겠어요","겠어","겠다고 한다"], answer: 0, explain: "'-겠습니다' is the formal polite ending for expressing future intent or promise in '합쇼체', suitable for formal communication like customer service statements.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-19-mr5ucjvd", question: "이 물건은 쉽게 _____, 조심히 다뤄야 한다.", options: ["깨지므로","깨트리므로","깨뜨려지므로","깨는 바람에"], answer: 0, explain: "'깨지다' is the correct passive form meaning \"to be broken.\" Combined with -(으)므로, it means \"because it breaks easily.\" '깨뜨려지다' is an example of an incorrect double passive.", language: "ko", level: "고급" },
  { id: "q-ko-고급-gemini-20-mr5ucjvd", question: "본 연구는 기존 문헌을 검토하고 새로운 데이터를 분석하여 결론에 도달하였 _____.", options: ["습니다","다","어요","었음"], answer: 0, explain: "'도달하였습니다' (or shortened to '도달했습니다') uses the formal polite '합쇼체' ending -습니다, which is appropriate for written academic reports.", language: "ko", level: "고급" },
  { id: "q-ko-중급-gemini-1-mr5ubw1v", question: "의자에 ___.", options: ["앉을 겁니다","앉으니까","앉고 있습니다","앉아 있습니다"], answer: 3, explain: "'-아/어 있다' expresses the state resulting from a completed action, such as 'is sitting.' '-고 있다' expresses an ongoing action.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-2-mr5ubw1v", question: "문이 ___.", options: ["열고 있어요","열을 거예요","열려 있어요","열으면"], answer: 2, explain: "'-아/어 있다' describes the state resulting from an action, like a door being open. '-고 있다' indicates an action in progress by an agent.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-3-mr5ubw1v", question: "비가 ___ 우산을 가져가세요.", options: ["오면","올 거예요","오니까","오고 있어요"], answer: 2, explain: "'- (으)니까' is used to express a reason or cause, often followed by a suggestion or command. 'Because it's raining, please take an umbrella.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-4-mr5ubw1v", question: "저는 배가 ___ 뭐 좀 먹어야겠어요.", options: ["고프면","고플 거예요","고프니까","고프고 있어요"], answer: 2, explain: "'- (으)니까' indicates the reason for an action. Here, 'because I'm hungry,' explains why the speaker needs to eat.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-5-mr5ubw1v", question: "주말에 시간이 ___ 같이 영화 보러 갈까요?", options: ["있으니까","있을 거예요","있고 있어요","있으면"], answer: 3, explain: "'- (으)면' is used to express a condition, meaning 'if' or 'when.' This sentence asks 'If you have time on the weekend, shall we go watch a movie?'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-6-mr5ubw1v", question: "이 버튼을 ___ 문이 열릴 거예요.", options: ["누를 거예요","누르면","누르니까","누르고 있어요"], answer: 1, explain: "'- (으)면' indicates a condition or hypothesis. It means 'if you press this button,' the door will open.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-7-mr5ubw1v", question: "내일 회의는 3시에 ___.", options: ["시작하니까","시작할 거예요","시작하면","시작하고 있어요"], answer: 1, explain: "'- (으)ㄹ 거예요' is used to express a future plan, intention, or prediction. This sentence means 'Tomorrow's meeting will start at 3 PM.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-8-mr5ubw1v", question: "저는 여름 방학에 제주도에 ___.", options: ["여행 가니까","여행 갈 거예요","여행 가면","여행 가고 있어요"], answer: 1, explain: "'- (으)ㄹ 거예요' expresses a future intention or plan. The speaker plans to travel to Jeju Island during the summer vacation.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-9-mr5ubw1v", question: "그는 어제 도서관에서 책을 ___.", options: ["읽었다고","읽느냐","읽었다","읽자"], answer: 2, explain: "The plain form '-다' is used for declarative statements in narration or informal contexts. 'He read a book at the library yesterday.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-10-mr5ubw1v", question: "선생님이 학생들에게 '숙제 다 ___?' 라고 물었다.", options: ["해라","하자","했냐","했다"], answer: 2, explain: "The plain interrogative ending '-냐' is used when asking a question in informal speech or reported speech. The teacher asked 'Did you do all your homework?'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-11-mr5ubw1v", question: "엄마가 나에게 '일찍 ___'고 말씀하셨다.", options: ["잔다","자냐","자라","자자"], answer: 2, explain: "The plain imperative ending '-라' (or '-아라/어라') is used for commands in informal speech or reported speech. My mom told me to 'sleep early.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-12-mr5ubw1v", question: "친구가 '우리 내일 같이 영화 ___'고 말했다.", options: ["본다","보냐","보자","봐라"], answer: 2, explain: "The plain propositive ending '-자' is used for suggestions in informal speech or reported speech. My friend said, 'Let's watch a movie together tomorrow.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-13-mr5ubw1v", question: "할머니, 맛있게 ___.", options: ["드시니까","드세요","드실 거예요","드시고 있어요"], answer: 1, explain: "'- (으)세요' is the polite imperative form used to give a respectful command or suggestion. 'Grandma, please eat deliciously.'", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-14-mr5ubw1v", question: "부장님께서 지금 회의실에 ___.", options: ["계시니까","계실 거예요","계시고 있어요","계세요"], answer: 3, explain: "'계시다' is the honorific form of '있다' (to be/exist). '계세요' is the polite declarative form used when speaking about someone of higher status.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-15-mr5ubw1v", question: "벽에 그림이 예쁘게 ___.", options: ["걸고 있어요","걸을 거예요","걸으면","걸려 있어요"], answer: 3, explain: "'-아/어 있다' expresses the state of an object that has been hung. '-고 있다' would imply someone is actively in the process of hanging it.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-16-mr5ubw1v", question: "날씨가 너무 ___ 옷을 따뜻하게 입으세요.", options: ["추우면","추울 거예요","춥고 있어요","추우니까"], answer: 3, explain: "'- (으)니까' indicates the reason for the following action or suggestion. Because the weather is cold, wear warm clothes.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-17-mr5ubw1v", question: "숙제를 다 ___ 놀러 가도 돼요.", options: ["끝내니까","끝낼 거예요","끝내고 있어요","끝내면"], answer: 3, explain: "'- (으)면' sets a condition, meaning 'if' or 'when.' You can go play if you finish your homework.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-18-mr5ubw1v", question: "사장님, 오늘 저녁 식사 같이 ___?", options: ["하시니까","하시면","하시고 있어요","하시겠어요"], answer: 3, explain: "'-시겠어요' is a polite and honorific way to ask if someone of higher status would like to do something.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-19-mr5ubw1v", question: "신문에서 그 영화가 정말 ___.", options: ["재미있을 거라고 한다","재미있으면 한다","재미있냐고 한다","재미있다고 한다"], answer: 3, explain: "This uses reported speech '- (으)ㄴ/는다고 하다.' '재미있다' is an adjective, so it uses '-다고 한다' in plain form.", language: "ko", level: "중급" },
  { id: "q-ko-중급-gemini-20-mr5ubw1v", question: "다음 주부터 새 학기가 ___.", options: ["시작되니까","시작되면","시작되고 있어요","시작될 거예요"], answer: 3, explain: "'- (으)ㄹ 거예요' expresses a future event or prediction. 'The new semester will start next week.'", language: "ko", level: "중급" },
  { id: "q-ko-초급-gemini-1-mr5nygjl", question: "김치 ___ 맛있어요.", options: ["은","는","이","가"], answer: 1, explain: "은/는 is a topic particle. '는' is used after a noun ending in a vowel, and 김치 ends in a vowel.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-2-mr5nygjl", question: "누가 문 ___ 열었어요?", options: ["이","을","는","가"], answer: 1, explain: "「을」是宾格助词，用于有收音的名词后。「문을 열었어요」中「문」是「열다」（打开）的宾语，故用「을」。主格助词「이/가」标记主语，但「문」在此处是动作对象而非发出者。", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-3-mr5nygjl", question: "저는 물 ___ 마셔요.", options: ["은","는","을","를"], answer: 2, explain: "「을」是宾格助词，用于有收音的名词后。「물」收辅音「ㄹ」，故用「을」而非「를」。「물을 마셔요」意为「喝水」。", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-5-mr5nygjl", question: "저는 매일 학교에 ___ (가다).", options: ["가요","갔어요","갑니다","가세요"], answer: 0, explain: "To form the present informal polite tense, -아요/-어요 is added to the verb stem. '가다' (to go) becomes '가요'.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-6-mr5nygjl", question: "어제 영화를 ___ (보다).", options: ["봐요","봤어요","봅니다","보세요"], answer: 1, explain: "To form the past informal polite tense, -았어요/-었어요 is added to the verb stem. '보다' (to see/watch) becomes '봤어요'.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-7-mr5nygjl", question: "저는 한국어를 ___ (배우다).", options: ["배워요","배웠어요","배우고","배울까요"], answer: 0, explain: "Korean sentences follow a Subject-Object-Verb (SOV) structure. The verb '배우다' (to learn) in the present tense is '배워요'.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-8-mr5nygjl", question: "오늘 날씨 ___ 정말 좋아요.", options: ["은","는","이","가"], answer: 3, explain: "이/가 is used to mark the subject of a sentence, often highlighting new information or stating a fact. 날씨 (weather) ends in a vowel, so '가' is used.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-9-mr5nygjl", question: "저는 책 ___ 읽어요.", options: ["은","는","을","를"], answer: 2, explain: "을/를 is an object particle. '을' is used after a noun ending in a consonant, and 책 (book) ends in a consonant.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-10-mr5nygjl", question: "저는 매일 운동 ___ (하다).", options: ["해요","했다","하고","합니까"], answer: 0, explain: "Verbs ending in -하다, like '운동하다' (to exercise), change to -해요 in the present informal polite tense.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-11-mr5nygjl", question: "어제 숙제 ___ (하다).", options: ["했어요","해요","합니다","할 거예요"], answer: 0, explain: "Verbs ending in -하다 change to -했어요 in the past informal polite tense. '숙제하다' (to do homework) becomes '숙제했어요'.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-12-mr5nygjl", question: "저는 밥을 먹어요. ___ 커피를 마셔요.", options: ["그리고","하지만","그래서","또는"], answer: 0, explain: "그리고 is a basic connective that means 'and' or 'and then', used to connect two sentences or clauses.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-13-mr5nygjl", question: "저는 매운 음식은 ___ 먹어요.", options: ["안","못","없","아니다"], answer: 0, explain: "To make a verb negative in Korean, place '안' directly before the verb. '안 먹어요' means 'I don't eat'.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-14-mr5nygjl", question: "이거 연필___?", options: ["이에요","입니다","이세요","이예요"], answer: 0, explain: "To form a question with '이다' (to be) in the informal polite style, you attach -이에요/-예요. 연필 (pencil) ends in a consonant, so '이에요' is used.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-15-mr5nygjl", question: "저는 사과를 좋아해요. 동생 ___ 오렌지를 좋아해요.", options: ["은","는","이","가"], answer: 0, explain: "「은」是主题助词，用于有收音的名词后。「동생」收辅音「ㅇ」，故用「은」。「동생은 오렌지를 좋아해요」意为「弟弟/妹妹喜欢橙子」。", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-16-mr5nygjl", question: "저기 ___ 제 친구예요.", options: ["은","는","이","가"], answer: 3, explain: "이/가 is used to introduce new information or identify someone/something. '저기' (over there) is followed by '가' to mark it as the subject being identified.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-17-mr5nygjl", question: "무슨 음악 ___ 들어요?", options: ["은","는","을","를"], answer: 2, explain: "을/를 is an object particle. '음악' (music) ends in a consonant, so '을' is used to mark it as the object of '듣다' (to listen).", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-18-mr5nygjl", question: "저는 친구와 백화점에서 옷을 ___ (사다).", options: ["사요","샀어요","사고","사세요"], answer: 0, explain: "The verb '사다' (to buy) in the present informal polite tense is '사요'. This question tests the present tense conjugation.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-19-mr5nygjl", question: "지난 주말에 뭐 ___ (하다)?", options: ["했어요","해요","합니다","하세요"], answer: 0, explain: "The phrase '지난 주말에' (last weekend) indicates a past event. '하다' (to do) becomes '했어요' in the past informal polite tense.", language: "ko", level: "초급" },
  { id: "q-ko-초급-gemini-20-mr5nygjl", question: "한국어 ___ 정말 재미있어요.", options: ["은","는","이","가"], answer: 1, explain: "은/는 marks the topic of the sentence. '한국어' (Korean language) ends in a vowel, so '는' is used to make a general statement about it.", language: "ko", level: "초급" },
  // ── th (60 items) ──
  { id: "q-th-a1-gemini-1-mr5uhgc4", question: "ฉัน ___ ตลาด.", options: ["ไป","มา","กิน","นอน"], answer: 0, explain: "The verb 'ไป' (pai) means 'to go' and is used when moving towards a destination. In this sentence, it indicates going to the market.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-2-mr5uhgc4", question: "เขา ___ ข้าว.", options: ["กิน","ดื่ม","นอน","ดู"], answer: 0, explain: "'กิน' (gin) is the verb used for eating solid food. The sentence means 'He eats rice'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-3-mr5uhgc4", question: "เด็กผู้หญิง ___ น้ำ.", options: ["ดื่ม","กิน","ทำ","พูด"], answer: 0, explain: "'ดื่ม' (deum) is the verb used specifically for drinking liquids. The sentence means 'The girl drinks water'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-4-mr5uhgc4", question: "ฉัน ___ นักเรียน.", options: ["เป็น","อยู่","คือ","มี"], answer: 0, explain: "'เป็น' (bpen) is used to express identity, nationality, or profession. Here, it states 'I am a student'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-5-mr5uhgc4", question: "คุณแม่ ___ ในครัว.", options: ["อยู่","เป็น","คือ","มี"], answer: 0, explain: "'อยู่' (yoo) is used to indicate location or existence of a person or object. The sentence means 'Mother is in the kitchen'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-6-mr5uhgc4", question: "พวกเรา ___ หนังสือหลายเล่ม.", options: ["มี","เป็น","อยู่","คือ"], answer: 0, explain: "'มี' (mee) means 'to have' or 'there is/are' and is used to express possession or existence. Here, it means 'We have many books'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-7-mr5uhgc4", question: "ฉันมีแมวสอง ___", options: ["ตัว","คน","อัน","เล่ม"], answer: 0, explain: "'ตัว' (dtua) is a classifier used for animals and some inanimate objects like clothes or furniture. In this case, it counts cats.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-8-mr5uhgc4", question: "เขาทำงาน ___ โรงเรียน.", options: ["ที่","กับ","ใน","บน"], answer: 0, explain: "'ที่' (tee) is a common preposition meaning 'at', 'in', or 'on' when referring to a general location. Here, it indicates working at school.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-9-mr5uhgc4", question: "ฉัน ___ กินผลไม้.", options: ["ชอบ","อยาก","ไป","มา"], answer: 0, explain: "'ชอบ' (chôp) means 'to like'. It is often followed by a verb or noun to express preference. The sentence means 'I like to eat fruit'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-10-mr5uhgc4", question: "เธอ ___ ภาษาไทย.", options: ["เรียน","ทำงาน","นอน","ดู"], answer: 0, explain: "'เรียน' (rian) means 'to study' or 'to learn'. The sentence means 'She studies Thai language'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-11-mr5uhgc4", question: "มีนักท่องเที่ยวสาม ___ ที่วัด.", options: ["คน","ตัว","อัน","เล่ม"], answer: 0, explain: "'คน' (kon) is the classifier used specifically for counting people. The sentence means 'There are three tourists at the temple'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-12-mr5uhgc4", question: "ฉันไปตลาด ___ เพื่อน.", options: ["กับ","ที่","ใน","จาก"], answer: 0, explain: "'กับ' (gàp) means 'with' and is used to indicate accompaniment. The sentence means 'I go to the market with a friend'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-13-mr5uhgc4", question: "A: กรุงเทพฯ คืออะไร? B: กรุงเทพฯ ___ เมืองหลวงของประเทศไทย.", options: ["คือ","เป็น","อยู่","มี"], answer: 0, explain: "「คือ」用于定义或等同关系，意为「就是」。「กรุงเทพฯ คือเมืองหลวง」表示「曼谷就是首都」，用于回答「是什么」的问题。前句问 คืออะไร 提示用 คือ 作答。", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-14-mr5uhgc4", question: "พ่อครัว ___ อาหารอร่อย.", options: ["ทำ","กิน","ดื่ม","ไป"], answer: 0, explain: "'ทำ' (tam) means 'to do' or 'to make'. In this context, it means 'The chef makes delicious food'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-15-mr5uhgc4", question: "หนังสืออยู่ ___ กระเป๋า.", options: ["ใน","บน","ใต้","ที่"], answer: 0, explain: "'ใน' (nai) means 'in' or 'inside' and is used when something is contained within another object. The book is inside the bag.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-16-mr5uhgc4", question: "เขามีรถหนึ่ง ___", options: ["คัน","ตัว","เล่ม","อัน"], answer: 0, explain: "'คัน' (kan) is a classifier used for vehicles like cars, bicycles, and also for umbrellas. The sentence means 'He has one car'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-17-mr5uhgc4", question: "เด็กๆ ___ โทรทัศน์.", options: ["ดู","ฟัง","พูด","อ่าน"], answer: 0, explain: "'ดู' (doo) means 'to watch' or 'to look at'. The sentence means 'The children watch television'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-18-mr5uhgc4", question: "บ้าน ___ สวยมาก.", options: ["นี้","นั้น","โน้น","ที่"], answer: 0, explain: "'นี้' (née) means 'this' and is a demonstrative used for something close to the speaker. The sentence means 'This house is very beautiful'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-19-mr5uhgc4", question: "___ เด็กผู้ชายกำลังเล่น.", options: ["พวก","ตัว","หนึ่ง","ที่"], answer: 0, explain: "'พวก' (puuak) is used before a noun to indicate a group or plurality. It means 'The boys are playing'.", language: "th", level: "A1" },
  { id: "q-th-a1-gemini-20-mr5uhgc4", question: "คุณครู ___ ภาษาไทย.", options: ["พูด","เขียน","ฟัง","อ่าน"], answer: 0, explain: "'พูด' (pôot) means 'to speak' or 'to talk'. The sentence means 'The teacher speaks Thai language'.", language: "th", level: "A1" },
  { id: "q-th-a2-gemini-1-mr5uhy7j", question: "ฉัน ___ พูดภาษาไทยได้นิดหน่อย", options: ["สามารถ","ควรจะ","ต้อง","กำลัง"], answer: 0, explain: "The word 'สามารถ' means 'can' or 'to be able to' and expresses ability. It fits with 'พูดภาษาไทยได้' to emphasize the ability to speak Thai.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-2-mr5uhy7j", question: "เขาอยากไปเที่ยวทะเล ___ ไม่มีเงิน", options: ["แต่","และ","เพราะว่า","ดังนั้น"], answer: 0, explain: "The conjunction 'แต่' means 'but' and is used to connect two contrasting ideas or clauses.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-3-mr5uhy7j", question: "กรุงเทพฯ ใหญ่ ___ เชียงใหม่", options: ["กว่า","เท่า","ที่สุด","เหมือน"], answer: 0, explain: "'กว่า' is used after an adjective to form a comparative, meaning 'more...than' or 'less...than'.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-4-mr5uhy7j", question: "เมื่อวานนี้ฉัน ___ ตลาด", options: ["ไป","จะไป","กำลังไป","ไปแล้ว"], answer: 0, explain: "「ไป」是趋向动词，表示过去发生的动作。「เมื่อวานนี้」提示过去时，故用「ไป」表示昨天去了市场。", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-5-mr5uhy7j", question: "คุณ ___ กินอาหารไทยเผ็ดๆ ไหม", options: ["เคย","ยัง","กำลัง","เพิ่ง"], answer: 0, explain: "'เคย' is used to ask or state if someone has ever done something, similar to the present perfect in English.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-6-mr5uhy7j", question: "เรา ___ ช่วยกันรักษาสิ่งแวดล้อม", options: ["ควรจะ","ต้อง","สามารถ","อยากจะ"], answer: 0, explain: "'ควรจะ' means 'should' and expresses advice or a recommendation about what is good or right to do.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-7-mr5uhy7j", question: "เขามาสาย ___ รถติดมาก", options: ["เพราะว่า","แต่","และ","หรือ"], answer: 0, explain: "'เพราะว่า' means 'because' and is used to introduce the reason or cause for something.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-8-mr5uhy7j", question: "ดอยอินทนนท์เป็นภูเขาที่สูง ___ ในประเทศไทย", options: ["กว่า","ที่สุด","เท่ากัน","เหมือน"], answer: 1, explain: "'ที่สุด' is used after an adjective to form the superlative degree, meaning 'the most' or 'the -est'.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-9-mr5uhy7j", question: "ฉัน ___ ไปญี่ปุ่นเลย", options: ["ยังไม่เคย","เคย","ไปแล้ว","จะไป"], answer: 0, explain: "'ยังไม่เคย...เลย' means 'have never...before' and expresses that an action has not been done up to the present moment.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-10-mr5uhy7j", question: "พรุ่งนี้มีสอบ คุณ ___ อ่านหนังสือเยอะๆ", options: ["ต้อง","ควรจะ","สามารถ","ไม่ต้อง"], answer: 0, explain: "'ต้อง' means 'must' and expresses obligation or necessity, indicating something that is required.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-11-mr5uhy7j", question: "เมื่อปีที่แล้วฉัน ___ เที่ยวต่างประเทศ", options: ["ไป","กำลังไป","จะไป","เคยไป"], answer: 0, explain: "「ไป」表示过去的动作。「เมื่อปีที่แล้ว」提示过去时，故用「ไป」表示去年去了国外旅游。", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-12-mr5uhy7j", question: "ฉันชอบอ่านหนังสือ ___ ฟังเพลง", options: ["และ","แต่","เพราะว่า","หรือ"], answer: 0, explain: "'และ' means 'and' and is used to connect two similar actions, ideas, or items in a list.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-13-mr5uhy7j", question: "ผู้ชายคนนี้สูง ___ ผู้หญิงคนนั้น", options: ["เท่ากับ","กว่า","ที่สุด","เหมือน"], answer: 0, explain: "'เท่ากับ' is used to express equality between two things, meaning 'as...as' or 'equal to'.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-14-mr5uhy7j", question: "คุณ ___ พูดภาษาอังกฤษได้ไหม", options: ["สามารถ","ควรจะ","ต้อง","ไม่สามารถ"], answer: 0, explain: "'สามารถ' means 'can' or 'to be able to' and is used to express capability or ability.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-15-mr5uhy7j", question: "ฉัน ___ ทำการบ้านเสร็จแล้ว", options: ["ได้","กำลัง","จะ","ควร"], answer: 0, explain: "When used before a verb with 'แล้ว' (already), 'ได้' can indicate that an action has been completed, similar to the present perfect.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-16-mr5uhy7j", question: "ฉันชอบกินข้าวผัด ___ ต้มยำกุ้ง", options: ["และ","แต่","เพราะว่า","หรือ"], answer: 0, explain: "'และ' means 'and' and is used to connect two nouns or phrases in a list.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-17-mr5uhy7j", question: "คุณ ___ ทิ้งขยะลงบนพื้น", options: ["ไม่ควร","ไม่ต้อง","ไม่สามารถ","ไม่อยาก"], answer: 0, explain: "'ไม่ควร' means 'should not' and expresses advice against an action or something that is not recommended.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-18-mr5uhy7j", question: "เมื่อคืนนี้ฝน ___ หนักมาก", options: ["ตก","กำลังตก","จะตก","เคยตก"], answer: 0, explain: "「ตก」用于天气，表示「下（雨）」。「ฝนตก」是「下雨」的固定搭配。「เมื่อคืนนี้」提示过去时，故填入「ตก」表示昨晚下了大雨。", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-19-mr5uhy7j", question: "เขา ___ ไปเที่ยวเชียงใหม่มาแล้วสองครั้ง", options: ["เคย","กำลัง","จะ","ไม่เคย"], answer: 0, explain: "'เคย' is used to describe a past experience, often translated as 'have ever' or 'have done something before'.", language: "th", level: "A2" },
  { id: "q-th-a2-gemini-20-mr5uhy7j", question: "ห้องนี้เล็ก ___ ห้องโน้น", options: ["กว่า","ที่สุด","เท่ากับ","เหมือน"], answer: 0, explain: "'กว่า' is used after an adjective to form a comparative, meaning 'smaller than' when paired with 'เล็ก' (small).", language: "th", level: "A2" },
  { id: "q-th-b1-gemini-1-mr5uik77", question: "เขา ___ ญี่ปุ่นเมื่อปีที่แล้ว", options: ["เคยไป","กำลังไป","ไป","จะไป"], answer: 2, explain: "「ไป」表示过去完成的动作。「เมื่อปีที่แล้ว」提示过去时，故用「ไป」。不用「เคยไป」（曾经去，经验）因为这是具体某次；不用「จะไป」（将要）和「กำลังไป」（正在）因为时态不符。", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-2-mr5uik77", question: "ฉัน ___ กินข้าวเช้าเลยตั้งแต่ตื่นนอน", options: ["ยังไม่เคย","กำลังจะ","ยังไม่","จะไม่ได้"], answer: 2, explain: "'ยังไม่' ใช้แสดงว่าการกระทำยังไม่เกิดขึ้นจนถึงขณะนี้ มักใช้คู่กับ 'เลย' เพื่อเน้นย้ำ และ 'ตั้งแต่' เพื่อบอกจุดเริ่มต้นของช่วงเวลา.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-3-mr5uik77", question: "ผู้ชาย ___ ใส่เสื้อสีน้ำเงินเป็นเพื่อนของฉัน", options: ["ซึ่ง","ที่","อัน","ผู้"], answer: 1, explain: "'ที่' เป็นคำสรรพนามเชื่อมความที่ใช้เพื่อเชื่อมประโยคย่อยที่ขยายคำนามที่อยู่ข้างหน้า เช่น คน สัตว์ สิ่งของ.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-4-mr5uik77", question: "จดหมายฉบับนี้ ___ เขียนโดยนักเรียน", options: ["ถูก","ได้","มี","เป็น"], answer: 0, explain: "'ถูก' ใช้เพื่อแสดงประโยคกรรมวาจก (passive voice) โดยที่ประธานในประโยคเป็นผู้ถูกกระทำ.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-5-mr5uik77", question: "ถ้าฝนตกหนัก พรุ่งนี้เรา ___ ไปเที่ยวไม่ได้", options: ["จะ","คง","น่าจะ","ต้อง"], answer: 0, explain: "โครงสร้าง 'ถ้า...จะ...' ใช้สำหรับเงื่อนไขที่เป็นไปได้ในปัจจุบันหรืออนาคต และผลลัพธ์ที่จะเกิดขึ้นจริง.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-6-mr5uik78", question: "เขาบอกว่าเขา ___ ไปทำงานพรุ่งนี้", options: ["จะไม่","ไม่ได้","ไม่เคย","ไม่"], answer: 0, explain: "เมื่อรายงานคำพูดที่เกี่ยวกับอนาคต เราจะใช้ 'จะไม่' เพื่อบอกการปฏิเสธในอนาคต.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-7-mr5uik78", question: "คุณเคยไปเที่ยวเชียงใหม่ ___?", options: ["หรือเปล่า","มาแล้ว","หรือไม่","หรือยัง"], answer: 3, explain: "'หรือยัง' ใช้ถามว่าการกระทำนั้นได้เกิดขึ้นแล้วหรือไม่จนถึงปัจจุบัน โดยมักใช้ร่วมกับ 'เคย'.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-8-mr5uik78", question: "ถ้าฉันมีเงินเยอะ ฉัน ___ ซื้อบ้านหลังใหญ่", options: ["จะ","ควรจะ","อาจจะ","คงจะ"], answer: 3, explain: "'ถ้า...คงจะ' ใช้สำหรับเงื่อนไขสมมุติที่ไม่เป็นจริงในปัจจุบัน หรือเป็นไปได้ยาก เพื่อแสดงผลลัพธ์ที่เป็นไปได้ภายใต้เงื่อนไขนั้น.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-9-mr5uik78", question: "เด็กชาย ___ หมาไล่กัดเมื่อวานนี้", options: ["โดน","ได้รับ","ถูก","ไป"], answer: 0, explain: "'โดน' ใช้เพื่อแสดงประโยคกรรมวาจก โดยที่ประธานเป็นผู้ถูกกระทำ มักใช้กับเหตุการณ์เชิงลบหรือไม่พึงประสงค์.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-10-mr5uik78", question: "นี่คือหนังสือ ___ ฉันอ่านจบเมื่อคืน", options: ["ซึ่ง","อัน","ที่","อย่าง"], answer: 2, explain: "'ที่' เป็นคำสรรพนามเชื่อมความที่ใช้เพื่อเชื่อมประโยคย่อยที่ขยายคำนามที่อยู่ข้างหน้า ไม่ว่าจะเป็นคน สัตว์ หรือสิ่งของ.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-11-mr5uik78", question: "เขาอยู่ที่นี่ ___ สองปีแล้ว", options: ["ตั้งแต่","เป็นเวลา","จนกระทั่ง","ในช่วง"], answer: 1, explain: "'เป็นเวลา' ใช้บอกระยะเวลาที่เหตุการณ์ได้เกิดขึ้นหรือดำเนินมาถึงปัจจุบัน.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-12-mr5uik78", question: "แม่ถามว่าฉัน ___ กินข้าวเย็นหรือยัง", options: ["จะ","ต้อง","ได้","ว่า"], answer: 2, explain: "'ได้' ในบริบทนี้ใช้เพื่อถามถึงการกระทำที่เกิดขึ้นแล้วหรือยัง ซึ่งเป็นส่วนหนึ่งของการรายงานคำถาม.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-13-mr5uik78", question: "ถ้าเธอไม่รีบ เธอ ___ รถไฟ", options: ["จะพลาด","อาจพลาด","คงพลาด","ต้องพลาด"], answer: 0, explain: "โครงสร้าง 'ถ้า...จะ...' ใช้สำหรับเงื่อนไขที่เป็นไปได้ในปัจจุบันหรืออนาคต และผลลัพธ์ที่จะเกิดขึ้นจริงในเชิงลบ.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-14-mr5uik78", question: "งานนี้ ___ เสร็จเรียบร้อยแล้วเมื่อวาน", options: ["ได้รับ","ได้","ถูก","เป็น"], answer: 2, explain: "「ถูก」是泰语标准被动标记，引出施事者。「ถูกเสร็จ」表示「被完成」。注意「ได้ถูก」是双重被动标记，非标准用法。", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-15-mr5uik78", question: "ฉัน ___ ไปทะเลเลยในชีวิตนี้", options: ["ยังไม่เคย","ไม่ได้","ได้","อาจ"], answer: 0, explain: "「ยังไม่เคย」表示「还没曾经」，用于否定经验。「ไปทะเลเลยในชีวิตนี้」表示一生中从未去过海边，故用「ยังไม่เคย」。", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-16-mr5uik78", question: "นักเรียน ___ สอบได้คะแนนสูงสุดได้รับทุนการศึกษา", options: ["ผู้ซึ่ง","ที่","คนที่","ผู้"], answer: 3, explain: "'ผู้' ใช้เป็นคำนำหน้าเพื่อระบุบุคคลที่มีคุณสมบัติหรือกระทำการบางอย่าง มักใช้ในภาษาทางการหรือข้อเขียน.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-17-mr5uik78", question: "ถ้าฉันเป็นนก ฉัน ___ บินไปรอบโลก", options: ["จะ","คงจะ","ต้อง","ควรจะ"], answer: 1, explain: "'ถ้าฉันเป็น...ฉันคงจะ...' ใช้สำหรับเงื่อนไขสมมุติที่ไม่เป็นจริงในปัจจุบัน หรือเป็นไปไม่ได้ เพื่อแสดงผลลัพธ์ที่เป็นไปได้ภายใต้เงื่อนไขนั้น.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-18-mr5uik78", question: "เขาบอกว่าเขาจะมาพรุ่งนี้ แต่ ___ เขาไม่มา", options: ["วันนี้","เมื่อวานนี้","ตอนนี้","เวลานี้"], answer: 0, explain: "「วันนี้」表示今天，作为时间状语通常放在句首或句末。「วันนี้เขาไม่มา」意为「今天他没来」，时间词在句首更自然。", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-19-mr5uik78", question: "เมื่อก่อนฉันเคยทำงานที่นี่ แต่ตอนนี้ฉัน ___ ไปแล้ว", options: ["ย้าย","กำลังย้าย","จะย้าย","ได้ย้าย"], answer: 0, explain: "'ย้าย' ในที่นี้หมายถึงการกระทำที่จบลงไปแล้วในอดีต โดยมีคำว่า 'แต่ตอนนี้' เป็นตัวแบ่งแยกระหว่างอดีตกับปัจจุบัน.", language: "th", level: "B1" },
  { id: "q-th-b1-gemini-20-mr5uik78", question: "ดอกไม้สวย ๆ ___ เด็ดโดยเด็กซน", options: ["ถูก","โดน","ได้","เป็น"], answer: 0, explain: "'ถูก' ใช้เพื่อแสดงประโยคกรรมวาจกเมื่อประธานเป็นผู้ถูกกระทำ โดยไม่จำเป็นต้องเป็นเรื่องเชิงลบเสมอไป แต่ในกรณีนี้เป็นพฤติกรรมที่ไม่เหมาะสม.", language: "th", level: "B1" },
  // ── yue (20 items) ──
  { id: "q-yue-初级-gemini-1-mr5ujum0", question: "我想 ___ 香港。", options: ["喺","去","有","係"], answer: 1, explain: "「去」 means 'to go to' a place, indicating movement towards a destination. 「喺」 means 'to be at' a place, indicating a static location.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-2-mr5ujum0", question: "佢 ___ 學生。", options: ["去","喺","係","唔"], answer: 2, explain: "「係」 is used to state what something or someone is, like 'is' or 'am' in English, followed by a noun or noun phrase.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-3-mr5ujum0", question: "我 ___ 食飯。", options: ["係","去","喺","唔"], answer: 3, explain: "「唔」 is placed before a verb to negate it, meaning 'not' or 'don't'. This is the standard way to form negative sentences in Cantonese.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-4-mr5ujum0", question: "___ 蘋果好甜。", options: ["喺個","呢個","唔個","咁個"], answer: 1, explain: "「呢個」 means 'this one' or 'this' (referring to something close to the speaker), while 「嗰個」 means 'that one' or 'that' (referring to something further away).", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-5-mr5ujum0", question: "快啲食飯 ___！", options: ["㗎","喎","啦","係"], answer: 2, explain: "「啦」 is used to indicate a suggestion, an imperative, or a change of state, making the sentence sound more friendly or urging.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-6-mr5ujum0", question: "我好肚餓，___ 我想食嘢。", options: ["喺","去","咁","係"], answer: 2, explain: "「咁」 can mean 'so' or 'then', indicating a consequence or a sequence of events, connecting the two clauses logically.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-7-mr5ujum0", question: "而家 ___ 鐘？", options: ["幾多","幾","點","乜嘢"], answer: 2, explain: "To ask 'what time is it?', we use 「點鐘」 for 'o'clock', so 「而家點鐘？」 means 'What time is it now?'.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-8-mr5ujum0", question: "我住 ___ 香港。", options: ["喺","去","有","係"], answer: 0, explain: "「喺」 means 'at' or 'in' and is used to indicate a static location where an action happens or someone resides.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-9-mr5ujum0", question: "佢 ___ 鍾意飲咖啡。", options: ["喺","係","咁","唔"], answer: 3, explain: "「唔」 is placed directly before a verb or adjective to negate it, meaning 'not' or 'don't like' in this context.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-10-mr5ujum0", question: "我想要 ___ 杯茶，唔要嗰個。", options: ["呢杯","嗰杯","邊杯","冇杯"], answer: 0, explain: "「呢杯」中「呢」是近指代词（这），「杯」是茶的正确量词。「我想要呢杯茶」意为「我要这杯茶」。粤语中名词和量词必须搭配，「茶」用量词「杯」而非「個」。", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-11-mr5ujum0", question: "佢係醫生 ___。", options: ["喎","啦","㗎","咁"], answer: 2, explain: "「㗎」 is used to express certainty, affirmation, or to confirm information, similar to 'it is a fact that' in English.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-12-mr5ujum0", question: "你有 ___ 本書？", options: ["點","咁","係","幾"], answer: 3, explain: "「幾」 is used to ask 'how many' when the number is expected to be relatively small, or to ask 'what' in questions about time.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-13-mr5ujum0", question: "我聽日 ___ 學校。", options: ["喺","係","去","有"], answer: 2, explain: "「去」 means 'to go to' and indicates movement towards a destination, like 'going to school'.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-14-mr5ujum0", question: "我 ___ 老師。", options: ["喺","去","係","唔"], answer: 2, explain: "「係」 is used to identify a noun, meaning 'am' or 'is' in English, establishing the speaker's profession.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-15-mr5ujum0", question: "佢話聽日會落雨 ___。", options: ["㗎","啦","喎","咁"], answer: 2, explain: "「喎」 is used to report what someone else said or to introduce new information, often with a slight sense of surprise or realization.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-16-mr5ujum0", question: "你病咗，___ 唔好返學。", options: ["喺","係","咁","去"], answer: 2, explain: "「咁」 is used to indicate a consequence or a suggestion based on a previous statement, meaning 'then' or 'so'.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-17-mr5ujum0", question: "呢度 ___ 間好靚嘅咖啡店。", options: ["去","係","喺","有"], answer: 3, explain: "「有」 means 'there is' or 'to have'. In this context, 「呢度有」 means 'there is (a beautiful coffee shop) here'.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-18-mr5ujum0", question: "佢 ___ 識講廣東話。", options: ["係","去","喺","唔"], answer: 3, explain: "「唔」 is used before a verb to negate it, meaning 'not' or 'don't'. Here, '唔識' means 'don't know how to'.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-19-mr5ujum0", question: "你要 ___ 橙定係嗰個？", options: ["喺個","呢個","唔個","咁個"], answer: 1, explain: "「呢個」 means 'this one' and 「嗰個」 means 'that one'. The question asks which one the person wants, implying a choice between items near and far.", language: "yue", level: "初级" },
  { id: "q-yue-初级-gemini-20-mr5ujum0", question: "你會幾 ___ 返屋企？", options: ["幾","咁","點","有"], answer: 2, explain: "「點」 is used with 「幾」 to ask 'what time' when referring to a specific point in time, as in 「幾點」 (what time).", language: "yue", level: "初级" },
  // ── zh (80 items) ──
  { id: "q-zh-hsk1-gemini-1-mr5nvncj", question: "___是我的书。", options: ["那","什么","这","哪"], answer: 2, explain: "「这」是近指代词，用于介绍或指代眼前的人或事。「这是我的书」表示近处的书属于说话人。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-2-mr5nvncj", question: "你是中国人 ___ ？", options: ["了","的","是","吗"], answer: 3, explain: "“吗” (ma) is a question particle placed at the end of a declarative sentence to turn it into a yes/no question.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-3-mr5nvncj", question: "他 ___ 学生。", options: ["是","有","在","喜欢"], answer: 0, explain: "“是” (shì) is used to equate two nouns or pronouns, indicating identity or classification, meaning 'to be'.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-4-mr5nvncj", question: "我 ___ 一个苹果。", options: ["是","有","在","喜欢"], answer: 1, explain: "“有” (yǒu) means 'to have' and is used to express possession of items or existence.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-5-mr5nvncj", question: "（指着眼前的东西）___ 是什么？", options: ["这","的","吗","那"], answer: 0, explain: "「这」是近指代词，用于指代眼前、近处的事物。括号中的情境提示用近指。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-6-mr5nvncj", question: "（指着远处的人）___ 是谁？", options: ["吗","这","的","那"], answer: 3, explain: "「那」是远指代词，用于指代远处的人或事物。括号中的情境提示用远指。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-7-mr5nvncj", question: "我有三 ___ 朋友。", options: ["个","本","杯","块"], answer: 0, explain: "“个” (gè) is a common general measure word used for many different nouns, including people and objects.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-8-mr5nvncj", question: "她有两 ___ 书。", options: ["个","本","杯","支"], answer: 1, explain: "“本” (běn) is the specific measure word used for books and other bound volumes.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-9-mr5nvncj", question: "请给我一 ___ 热水（用玻璃杯喝）。", options: ["杯","个","本","支"], answer: 0, explain: "「杯」是用于杯装饮料的量词。括号中的情境明确使用杯子。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-10-mr5nvncj", question: "___ 是星期一，我们要上班。", options: ["今天","明天","昨天","后天"], answer: 0, explain: "「今天」表示说话当天。星期一上班的语境提示是说话当天发生的事。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-11-mr5nvncj", question: "现在是下午3点，我们 ___ 见。", options: ["明天","现在","昨天","下周"], answer: 1, explain: "「现在」表示说话时刻。括号中给出当前时间提示用「现在见」。", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-12-mr5nvncj", question: "这是漂亮 ___ 衣服。", options: ["的","吗","了","有"], answer: 0, explain: "“的” (de) is used to connect an adjective to the noun it describes, especially when the adjective is more than one syllable.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-13-mr5nvncj", question: "我吃饭 ___ 。", options: ["吗","的","是","了"], answer: 3, explain: "“了” (le) indicates the completion of an action or a change in state. Here, it shows the action of eating is finished.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-14-mr5nvncj", question: "他 ___ 老师。", options: ["有","是","不","吗"], answer: 1, explain: "“是” (shì) is used to state identity or classification, such as 'He is a teacher'.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-15-mr5nvncj", question: "我 ___ 钱。", options: ["不","没","是","没有"], answer: 3, explain: "“没有” (méiyǒu) is the standard way to negate '有' (to have), meaning 'don't have' or 'there isn't'.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-16-mr5nvncj", question: "他 ___ 名字是什么？", options: ["的","了","吗","是"], answer: 0, explain: "“的” (de) is used to indicate possession, similar to 's in English, connecting the possessor to the possessed item.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-17-mr5nvncj", question: "你好 ___ ？", options: ["的","吗","了","是"], answer: 1, explain: "“吗” (ma) is a question particle that forms a yes/no question when placed at the end of a sentence.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-18-mr5nvncj", question: "我 ___ 学生。", options: ["不是","不","没","没有"], answer: 0, explain: "“不是” (búshì) is the negative form of '是', meaning 'is not' or 'am not'.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-19-mr5nvncj", question: "这是我的书，___ 是你的书。", options: ["那","这","的","吗"], answer: 0, explain: "“那” (nà) means 'that' and is used to refer to something further away or distinct from 'this'.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk1-gemini-20-mr5nvncj", question: "老师回家 ___ 。", options: ["吗","的","是","了"], answer: 3, explain: "“了” (le) indicates the completion of an action, meaning the teacher has gone home.", language: "zh", level: "HSK1" },
  { id: "q-zh-hsk2-gemini-1-mr5nw9jq", question: "昨天我去看电影___。", options: ["在","了","还","没"], answer: 1, explain: "“了”是动词或句末的助词，表示动作的完成。Yesterday, I watched a movie. '了' is used after a verb or at the end of a sentence to indicate the completion of an action.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-2-mr5nw9jq", question: "请你___这本书给我。", options: ["对","在","把","是"], answer: 2, explain: "“把”字句用于将宾语提前，强调对宾语的处理或结果。结构为：主语 + 把 + 宾语 + 动词 + 其他成分。The '把' construction is used to place the object before the verb, emphasizing what happens to the object. The structure is Subject + 把 + Object + Verb + Other elements.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-3-mr5nw9jq", question: "这件衣服 ___ 贵。", options: ["很","最","比较","非常"], answer: 2, explain: "「比较」表示程度适中，有相对意味。「这件衣服比较贵」表示价格高于一般但不算非常贵。", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-4-mr5nw9jq", question: "在所有水果中，我 ___ 喜欢吃苹果。", options: ["很","最","比较","太"], answer: 1, explain: "「最」表示在多个事物中程度最高。「在所有水果中」明确是比较范围，故用「最」。", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-5-mr5nw9jq", question: "___下雨了，___我们没去公园。", options: ["虽然...但是","因为...所以","如果...就","除了...以外"], answer: 1, explain: "“因为...所以...”用于表达因果关系。“因为”引出原因，“所以”引出结果。'因为...所以...' is used to express a cause and effect relationship. '因为' introduces the reason, and '所以' introduces the result.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-6-mr5nw9jq", question: "我___说一点儿汉语。", options: ["要","可以","能","会"], answer: 3, explain: "“会”表示习得的技能或能力。在这里，它表示“能够”做某事。'会' indicates a learned skill or ability. Here, it means 'can' in the sense of 'know how to'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-7-mr5nw9jr", question: "他病了，今天___来上课。", options: ["不会","不能","不可以","没有"], answer: 1, explain: "“能”表示身体能力或可能性。“不能”表示由于身体状况或某种限制而无法做到。'能' indicates physical ability or possibility. '不能' means 'cannot' due to a physical constraint or impossibility.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-8-mr5nw9jr", question: "这里___抽烟吗？", options: ["会","要","可以","能"], answer: 2, explain: "“可以”用于请求或给予许可。这里是询问“在这里吸烟是否被允许？”'可以' is used to ask for or grant permission. Here, it asks 'Is it allowed to smoke here?'", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-9-mr5nw9jr", question: "你喜欢喝茶___咖啡？", options: ["或者","和","还是","跟"], answer: 2, explain: "“还是”用于连接疑问句中的两个选择。'还是' is used to connect two choices in an interrogative sentence (a question).", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-10-mr5nw9jr", question: "晚上我会在家看书___看电视。", options: ["和","还是","跟","或者"], answer: 3, explain: "“或者”用于连接陈述句中的两个选择。'或者' is used to connect two choices in a declarative sentence (a statement).", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-11-mr5nw9jr", question: "昨天晚上我看了两部电影___。", options: ["着","了","过","在"], answer: 1, explain: "动词后的“了”表示动作已经完成。'了' after the verb '看' indicates that the action of watching two movies has been completed.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-12-mr5nw9jr", question: "他___作业写完了。", options: ["在","给","对","把"], answer: 3, explain: "“把”字句用于表示对宾语（作业）的处理已经完成。The '把' construction is used here to show that the homework (object) has been written completely (result).", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-13-mr5nw9jr", question: "这本书 ___ 有意思，比那本好看多了。", options: ["最","非常","比较","很"], answer: 2, explain: "「比较」用于对比语境。后半句「比那本好看」提示这是相对比较，故用「比较」。", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-14-mr5nw9jr", question: "她的成绩是全班第一名，她是班里学习 ___ 好的学生。", options: ["非常","很","比较","最"], answer: 3, explain: "「最」表示最高程度。「全班第一名」明确她优于所有同学，故用「最」。", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-15-mr5nw9jr", question: "他生病了，___没来上班。", options: ["但是","然后","因为","所以"], answer: 3, explain: "“所以”引出前面原因导致的结果或后果。这里，生病（原因）导致没来上班（结果）。'所以' introduces the result or consequence of the preceding cause. Here, the cause (being sick) leads to the result (not coming to work).", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-16-mr5nw9jr", question: "明天可能___下雨。", options: ["能","可以","要","会"], answer: 3, explain: "“会”也可以表示预测或未来的可能性，意为“将会”或“可能”。'会' can also indicate a prediction or a future possibility, meaning 'will' or 'likely to'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-17-mr5nw9jr", question: "太吵了，我 ___ 你说什么。", options: ["听不见","听不清","听见","听得见"], answer: 1, explain: "「听不清」表示听到的声音但不清晰。「太吵了」是程度副词提示无法清晰分辨，故用「听不清」。", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-18-mr5nw9jr", question: "我___坐在这里吗？", options: ["会","能","可以","要"], answer: 2, explain: "“可以”用于请求许可。这里是询问“我能否坐在这里？”'可以' is used to ask for permission. Here, it asks 'May I sit here?'", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-19-mr5nw9jr", question: "你想吃面条___米饭？", options: ["或者","和","还是","跟"], answer: 2, explain: "“还是”用于在疑问句中提供两个或多个选择。'还是' is used to present alternative choices in a question.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk2-gemini-20-mr5nw9jr", question: "你可以坐地铁___坐公共汽车去。", options: ["和","跟","还是","或者"], answer: 3, explain: "“或者”用于在陈述句中提供替代选项，意为“或”。'或者' is used to offer alternatives in a statement, meaning 'or'.", language: "zh", level: "HSK2" },
  { id: "q-zh-hsk3-gemini-1-mr5nwwir", question: "我的手机昨天___小偷拿走了。", options: ["被","把","对","向"], answer: 0, explain: "「被」是书面语中标准的被动标记，引出施事者。「把/对/向」不能引出施事者作被动。", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-2-mr5nwwir", question: "请你___这本书放在桌子上。", options: ["把","是","在","给"], answer: 0, explain: "The \"把\" construction is used to move the object of the verb before the verb, emphasizing the action's effect on the object. It always precedes the object and the main verb, followed by other elements like a place or result.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-3-mr5nwwir", question: "他很忙，___吃饭的时间___没有。", options: ["连...也","不只...还","无论...都","只要...就"], answer: 0, explain: "\"连...都/也\" is used to emphasize an extreme or unexpected situation, meaning \"even...\". In this sentence, it emphasizes that he is so busy he doesn't even have time to eat.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-4-mr5nwwir", question: "学习中文___有意思。", options: ["更","非常","越来越","最"], answer: 2, explain: "\"越来越\" indicates a gradual change or increase in degree, meaning \"more and more\". It is used before an adjective or a psychological verb to describe a continuous trend.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-5-mr5nwwir", question: "他___会说中文，___会写汉字。", options: ["虽然...但是","不但...而且","因为...所以","如果...就"], answer: 1, explain: "\"不但...而且\" is a conjunction used to connect two clauses or phrases, indicating \"not only...but also...\". It shows that both situations or qualities are true.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-6-mr5nwwir", question: "___外面下雨，___我们还是要去公园。", options: ["因为...所以","不但...而且","如果...就","虽然...但是"], answer: 3, explain: "\"虽然...但是\" is a pair of conjunctions meaning \"although...but...\", used to express a contrast or concession between two clauses. It acknowledges one fact while presenting another contrasting fact.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-7-mr5nwwir", question: "___他去了上海，我们就没见过面了。", options: ["直到","自从","一直","当"], answer: 1, explain: "\"自从\" means \"since\" a certain time or event, indicating the starting point of a continuous action or state. It specifies the beginning of a period during which something has happened or been true.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-8-mr5nwwir", question: "我等他 ___ 晚上九点才回来。", options: ["自从","到","直到","从"], answer: 2, explain: "「直到」表示动作或状态延续到某个时间点。「等他直到晚上九点」表示等待动作持续到九点。", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-9-mr5nwwir", question: "那个盘子不小心___我打碎了。", options: ["被","把","对","给"], answer: 0, explain: "「被」是书面语被动标记，引出施事者。「把」是主动处置标记；「对/给」在此句法位置不能作被动。", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-10-mr5nwwir", question: "你可以___这些书还给图书馆吗？", options: ["给","在","把","是"], answer: 2, explain: "The \"把\" construction places the object (这些书) before the verb (还给) to emphasize how the object is handled or affected by the action. It implies a disposal or handling of the object.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-11-mr5nwwir", question: "这道题太难了，___老师___不会做。", options: ["除了...还","连...都","只有...才","不管...都"], answer: 1, explain: "\"连...都/也\" emphasizes an extreme case, meaning \"even the teacher doesn't know how to do it\", highlighting the difficulty of the problem.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-12-mr5nwwir", question: "天气___冷了，你多穿点衣服。", options: ["特别","越来越","非常","很"], answer: 1, explain: "\"越来越\" describes a progressive change, indicating that the weather is becoming \"more and more\" cold. It shows a continuous increase in the degree of coldness.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-13-mr5nwwir", question: "小明___学习好，___运动也棒。", options: ["虽然...但是","因为...所以","不但...而且","如果...就"], answer: 2, explain: "\"不但...而且\" connects two positive attributes of Xiaoming, showing that he is good at both studying and sports. It expresses a combination of two advantages.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-14-mr5nwwir", question: "___他很累，___他还是坚持完成了工作。", options: ["如果...就","虽然...但是","因为...所以","不但...而且"], answer: 1, explain: "\"虽然...但是\" expresses a contrast between being tired and still persisting, meaning \"although he was tired, he still persevered.\" It highlights the dedication despite fatigue.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-15-mr5nwwir", question: "___毕业以后，我们就很少联系了。", options: ["直到","一直","自从","从"], answer: 2, explain: "\"自从\" indicates the starting point of a period or event, meaning \"since graduating\", they have had little contact. It marks the beginning of a sustained situation.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-16-mr5nwwir", question: "我要工作___午饭时间。", options: ["自从","在","从","直到"], answer: 3, explain: "\"直到\" specifies the ending point of an action, meaning \"I will work until lunchtime.\" It defines the limit or duration of an activity.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-17-mr5nwwir", question: "我的钱包___偷了。", options: ["是","在","给","被"], answer: 3, explain: "\"被\" is used to form a passive sentence when the subject is the receiver of the action, and the agent is either unknown or not emphasized. Here, it indicates the wallet was stolen.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-18-mr5nwwir", question: "请你___垃圾扔进垃圾桶。", options: ["让","给","向","把"], answer: 3, explain: "The \"把\" construction is used when the verb (扔) acts upon a definite object (垃圾), resulting in a change of its location or state (扔进垃圾桶). It focuses on the handling of the object.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-19-mr5nwwir", question: "这个孩子很聪明，___ 三岁的孩子 ___ 会写的字。", options: ["连...都","不但...而且","虽然...但是","因为...所以"], answer: 0, explain: "「连...都」用于强调极端情况，意为「甚至」。「连三岁的孩子都会写的字」强调这个字非常简单，连幼儿都会写。", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk3-gemini-20-mr5nwwir", question: "他的中文说得___流利了。", options: ["非常","特别","最","越来越"], answer: 3, explain: "\"越来越\" describes a continuous improvement, meaning his Chinese speaking is becoming \"more and more fluent.\" It indicates a progressive and ongoing development.", language: "zh", level: "HSK3" },
  { id: "q-zh-hsk4-gemini-1-mqzvxis4", question: "___ 你同意，我们就开始这个项目。", options: ["如果","既然","与其","只有"], answer: 0, explain: "The structure \"如果...就...\" (rúguǒ...jiù...) is used to express a conditional relationship, meaning \"if...then...\". Here, it indicates that if you agree, then the project will start.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-2-mqzvxis4", question: "这道菜的味道真好，我很快就吃___ 了。", options: ["好","完","到","住"], answer: 1, explain: "The resultative complement \"完\" (wán) indicates the completion of an action. \"吃完了\" means that the action of eating has been completed.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-3-mqzvxis4", question: "___ 浪费时间看电视，___ 多读几本书。", options: ["如果...就","既然...就","与其...不如","因为...所以"], answer: 2, explain: "The structure \"与其...不如...\" (yǔqí...bùrú...) is used to express a preference, meaning \"rather than A, it's better to B\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-4-mqzvxis4", question: "我把作业写___ 了，现在可以出去玩了。", options: ["完","到","住","好"], answer: 3, explain: "The resultative complement \"好\" (hǎo) indicates that an action has been completed and the result is satisfactory or ready. \"写好了\" means the homework is finished and ready.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-5-mqzvxis4", question: "我的钥匙找不___ 了，你帮我找找好吗？", options: ["住","好","完","到"], answer: 3, explain: "The resultative complement \"到\" (dào) indicates the successful achievement of an action or goal. \"找不到\" means unable to find.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-6-mqzvxis4", question: "___ 他知道错了，你就原谅他吧。", options: ["如果","既然","与其","只要"], answer: 1, explain: "The structure \"既然...就...\" (jìrán...jiù...) is used to express a logical consequence based on a known premise, meaning \"since/given that...then...\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-7-mqzvxis4", question: "请你记___ 我的手机号码，下次联系我就方便了。", options: ["好","完","到","住"], answer: 3, explain: "The resultative complement \"住\" (zhù) can indicate holding firm, stopping, or remembering something firmly. \"记住\" means to remember something firmly and not forget it.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-8-mqzvxis4", question: "这幅画 ___ 谁画的？", options: ["给","在","是","让"], answer: 2, explain: "「是……的」结构用于强调过去已发生动作的时间、地点、方式等。这里强调动作的发出者「谁」，故用「是」。", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-9-mqzvxis4", question: "如果下雨，我们___ 在家看电影。", options: ["就","才","却","都"], answer: 0, explain: "The particle \"就\" (jiù) often appears in the second clause of an \"如果...就...\" conditional sentence, indicating the consequence.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-10-mqzvxis4", question: "我的电脑___ 弟弟不小心弄坏了。", options: ["被","给","让","把"], answer: 2, explain: "The word \"让\" (ràng) can be used to form a passive sentence, indicating that the action was caused by someone or something, often with an undesirable outcome.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-11-mqzvxis4", question: "___ 你不喜欢吃这个，我们 ___ 可以点别的。", options: ["既然...就","虽然...但是","因为...所以","不但...而且"], answer: 0, explain: "「既然……就」表示基于已知事实推出结论。「既然你不喜欢」是已知前提，「我们就可以点别的」是据此得出的结论。", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-12-mqzvxis4", question: "我昨天买的衬衫___ 弄脏了，还没穿呢。", options: ["被","把","对","向"], answer: 0, explain: "「被」用于无施事者的被动句。「衬衫被弄脏了」表示衬衫被某个未指明的人或事弄脏。", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-13-mqzvxis4", question: "这部电影我还没看___，你别剧透！", options: ["好","完","到","住"], answer: 1, explain: "The resultative complement \"完\" (wán) indicates the completion of an action. \"还没看完\" means the action of watching has not yet been completed.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-14-mqzvxis4", question: "___ 每天都努力学习，你的中文水平一定会提高。", options: ["既然","如果","不如","除非"], answer: 1, explain: "The structure \"如果...就...\" (rúguǒ...jiù...) is used to express a conditional relationship, meaning \"if...then...\". Here, if you study hard every day, your Chinese will improve.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-15-mqzvxis4", question: "这件礼物 ___ 谁送给你的？", options: ["在","是","把","让"], answer: 1, explain: "「是……的」结构用于强调过去已发生动作的时间、地点、方式等。这里强调动作的发出者「谁」，故用「是」。", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-16-mqzvxis4", question: "___ 总是抱怨，___ 想办法解决问题。", options: ["如果...就","既然...就","与其...不如","因为...所以"], answer: 2, explain: "The structure \"与其...不如...\" (yǔqí...bùrú...) expresses a preference, meaning \"rather than always complaining, it's better to think of ways to solve the problem\".", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-17-mqzvxis5", question: "他因为太忙，忘记了那件事，___ 他的朋友很生气。", options: ["所以","如果","既然","让"], answer: 3, explain: "The word \"让\" (ràng) here means \"to make\" or \"to cause\", indicating that his forgetting caused his friend to be angry.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-18-mqzvxis5", question: "我昨天买的手机，今天早上就摔___ 了。", options: ["好","完","到","坏"], answer: 3, explain: "The resultative complement \"坏\" (huài) indicates that something is broken or damaged as a result of an action. \"摔坏了\" means it was broken by falling.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-19-mqzvxis5", question: "你___ 答应了别人，___ 要做到。", options: ["如果...就","既然...就","与其...不如","只有...才"], answer: 1, explain: "The structure \"既然...就...\" (jìrán...jiù...) expresses a logical consequence. Since you've promised others, then you must keep your word.", language: "zh", level: "HSK4" },
  { id: "q-zh-hsk4-gemini-20-mqzvxis5", question: "我们 ___ 去年夏天认识的。", options: ["在","是","把","让"], answer: 1, explain: "「是……的」结构强调动作发生的时间。「去年夏天」是时间状语，被「是」和「的」框起来强调。", language: "zh", level: "HSK4" },
];
